head.script:
/**
 * 화면명 : KPX오더요청등록
 * 화면ID : tp_801_01_04b
 */
// tp_801_01_01t, tp_801_01_04b 화면 통합(다른 탭화면이 삭제되었음)
// lo_100_03_03p 삭제되어 f_tplCommCdPop() 사용안함
// ASIS : ds_shipmentIndicationCommodity : ctrtWrkPathSeq 컬럼에 값이 있어도(ex:1) 콤보값인 ds_ctrtWrkPath에 데이터가 없으면 "" 처리됨
// 요청처, 청구처 데이터가 없어도 DB에서 빈로우 한줄이 넘어오기때문에 콤보박스에 "" : "" 표시됨(ASIS는 빈한줄)

scwin.regId = $c.data.getMemInfo("userId");
scwin.userNm = $c.data.getMemInfo("userNm");
scwin.userMpNo = $c.data.getMemInfo("userMpNo");
scwin.lobranCd = $c.data.getMemInfo("lobranCd");

scwin.strCurDate = $c.date.getServerDateTime("yyyyMMdd"); // 현재일자

scwin.bizDivCntrYn = DsConstants.YN_NO;	 // 사업부문컨테이너여부
scwin.bizDivBulkYn = DsConstants.YN_YES; // 사업부문벌크여부
scwin.bizDivTplYn = DsConstants.YN_YES;	 // 사업부문3자물류여부

// hidden 컴퍼넌트
scwin.hid_ctrtRepClntNo = "";       // 대표거래처번호
scwin.hid_ctrtNo = "";              // 계약번호
scwin.hid_odrJobType = "";          // 오더 작업구분 : 신규(DGauceConstants.TB_JOB_INSERT), 수정(DGauceConstants.TB_JOB_UPDATE)

// Popup Check 용 Hidden 값
scwin.hid_chkCtrtClntNo = "";       // 계약처
scwin.hid_chkReqClntNo = "";        // 요청처
scwin.hid_chkBilgClntNo = "";       // 청구처
scwin.hid_chkRealMchtClntNo = "";   // 실화주
scwin.hid_chkDmndNo = "";           // 수요가
scwin.hid_chkSellLodeptCd = "";     // 매출부서
scwin.hid_chkBilgLodeptCd = "";     // 청구부서
scwin.hid_chkLineCd = "";           // LINE
scwin.hid_chkBlNo = "";             // B/L 번호
scwin.hid_chkCvsslMgntNo = "";      // 본선관리번호
scwin.hid_chkDptWrkPlCd = "";       // 출발작업장
scwin.hid_chkArvWrkPlCd = "";       // 도착작업장
scwin.hid_mchtOdrKndCd = "";
//scwin.hid_chkReterieve = "";        // 조회 여부 확인

// EDI 맵핑 조회조건 용 Hidden 값
scwin.hid_docCd = "ODRKND_001";     // 문서코드 - 화주오더종류
scwin.hid_wrkPlCd = "999";          // 작업장코드 
scwin.hid_itemCd = "";              // 항목코드 
scwin.hid_osideCd = "";             // 외부코드

// 조회조건 용 logseq 값
scwin.hid_logSeq = "";

scwin.defaultFontColor = "#000000";

scwin.vaildObj = new Array(); // Vaildation 확인 Object 설정

scwin.ds_shipmentIndicationCommodity_row = -1;
scwin.ds_mchtOdrKndCd_reterieveYn = "N";
//-------------------------------------------------------------------------
// 화면 로딩시
//-------------------------------------------------------------------------
scwin.onpageload = function () {
    // 공통코드 콤보박스 SET
    const codeOptions = [
        { grpCd: "SD161", compID: "acb_odrCnclItemCd" } //귀책사유
    ];
    $c.data.setCommonCode(codeOptions);

    // if (lc_ctrtNo.getText(true) != "선택") {
    if (lc_ctrtNo.getValue()) {
        scwin.f_RetrieveCtrtWrkPath(lc_ctrtNo.getValue());
    }    
};

//-------------------------------------------------------------------------
// UDC Completed
//-------------------------------------------------------------------------
scwin.onUdcCompleted = async function () {
    //$p.setTimeout(function () {
        // 초기화
        await scwin.f_defaultValue();

        scwin.f_setFrameOrderSearchQueryCondition();
    //}, { "delay": 50 });
};

//-------------------------------------------------------------------------
// 오더요청 조회 조건 설정
//-------------------------------------------------------------------------
scwin.f_setFrameOrderSearchQueryCondition = async function () {
    scwin.params = $c.data.getParameter();

    if (!$c.util.isEmpty(scwin.params["repClntNo"])) {
        scwin.hid_ctrtRepClntNo = scwin.params["repClntNo"];
    }

    if (!$c.util.isEmpty(scwin.params["clntNo"])) {
        ed_clntNo.setValue(scwin.params["clntNo"]);
    }

    if (!$c.util.isEmpty(scwin.params["clntNm"])) {
        ed_clntNm.setValue(scwin.params["clntNm"]);
    }

    if (!$c.util.isEmpty(scwin.params["mchtOdrKndCd"])) {
        scwin.hid_mchtOdrKndCd = scwin.params["mchtOdrKndCd"];
    }

    if (!$c.util.isEmpty(scwin.params["logSeq"])) {
        scwin.hid_logSeq = scwin.params["logSeq"];
    }

    ed_mchtOdrNo.setValue(scwin.params["mchtOdrNo"]);
    ed_mcomOdrNo.setValue(scwin.params["mcomOdrNo"]);

    // 테스트데이터
    // scwin.hid_ctrtRepClntNo = "247741";
    // ed_clntNo.setValue("117299");
    // scwin.hid_mchtOdrKndCd = "s";
    // ed_mchtOdrNo.setValue("2000026");
    // scwin.hid_logSeq = 1;

    // // EDI MAPPING 조회 조건
    dma_ediMappingSearch.set("docCd", scwin.hid_docCd);
    dma_ediMappingSearch.set("wrkPlCd", scwin.hid_wrkPlCd);
    dma_ediMappingSearch.set("clntNo", scwin.hid_ctrtRepClntNo); //거래처번호
    dma_ediMappingSearch.set("ctrtNo", lc_ctrtNo.getValue()); //계약번호

    $c.sbm.execute(sbm_reterieveMchtOdrKnd);

    // if (ds_mchtOdrKndCd.getRowCount() > 0) {
    //     acb_mchtOdrKndCd.setValue(scwin.hid_mchtOdrKndCd);
    // } else {
    //     let newRow = ds_mchtOdrKndCd.insertRow();
    //     ds_mchtOdrKndCd.setRowPosition(newRow);
    //     ds_mchtOdrKndCd.setCellData(0, "osideCd", scwin.params["mchtOdrKndCd"]);
    //     ds_mchtOdrKndCd.setCellData(0, "osideCdNm", scwin.params["mchtOdrKndNm"]);
    // }    
};

//-------------------------------------------------------------------------
// 계약작업경로  콤보 조회
//-------------------------------------------------------------------------
scwin.f_RetrieveCtrtWrkPath = function (ctrtNo) {    
    dma_condCtrtWrkPath.set("sysCd", "BulkOrderEBC");
    dma_condCtrtWrkPath.set("queryId", "retrieveContractWorkPathComboList");
    dma_condCtrtWrkPath.set("param1", ctrtNo);
    dma_condCtrtWrkPath.set("param2", acb_odrKndCd.getValue());

    $c.sbm.execute(sbm_reterieveCtrtWrkPath);
}

//-------------------------------------------------------------------------
// 초기화
//-------------------------------------------------------------------------
scwin.f_defaultValue = async function () {
    scwin.f_dsOrderSearchHeader(); // 오더 조회조건
    scwin.f_dsOrderQueryConditionHeader(); // 오더 조회조건 - 계약 거래처 조회
    scwin.f_dsLobranQueryConditionHeader(); // 물류점소

    // 조회 조건 초기화
    scwin.f_FieldClear();

    // 출발일자, 도착일자 초기값 설정
    //ica_wrkStDt.setValue(scwin.strCurDate);
    ica_wrkEndDt.setValue(scwin.strCurDate);

    // 오더 담당 정보 설정
    ed_odrPicNm.setValue(scwin.userNm);
    ed_odrPicTelNo.setValue(scwin.userMpNo);

    // 로그인 사용자 물류점소 - 운송(매출)부서 조회
    dma_lobranQueryCondition.set("deptmentCd", DsConstants.TRANS_DEPARTMENT); // 운송부서
    ds_lobranTrans.setJSON([]);
    await $c.sbm.execute(sbm_retrieveLobranTrans);

    // 로그인 사용자 물류점소 - 영업(청구)부서 조회
    dma_lobranQueryCondition.set("deptmentCd", DsConstants.SALES_DEPARTMENT); // 영업부서
    ds_lobranSales.setJSON([]);
    await $c.sbm.execute(sbm_retrieveLobranSales);

    $c.gus.cfEnableKeyData();
    $c.gus.cfDisableKey();

    // PopUp 이미지 버튼을 비활성화 시킨다.
    scwin.f_DisablePopUpObj();

    // 오더 확정 버튼 비활성화
    $c.gus.cfDisableObjects([btn_orderSheetPrint]);

    $c.gus.cfEnableObjects([btn_PopUp1]);

    // 그리드 행추가 / 삭제 /취소 버튼 비활성화
    $c.gus.cfDisableAllBtn();

    // 오더 종류에 따른 화면 설정
    scwin.f_defaultOdrKndSetting();

    $c.gus.cfDisableObjects(tbl_order);

    tbx_totalRows.setValue("0");

    //ed_clntNo.focus();
};

//-------------------------------------------------------------------------
// 조회 조건 초기화
//-------------------------------------------------------------------------
scwin.f_FieldClear = function () {
    $c.gus.cfInitObjects(tbl_searchCondition);

    // TOBE : 맨처음 조회시에는 포커스 안가게 처리(포커스가가면 화주오더종류가 다시 조회됨)
    if (scwin.ds_mchtOdrKndCd_reterieveYn == "Y") {
        ed_clntNo.focus();
    }
};

//-------------------------------------------------------------------------
// DataSet Header 정의 - 오더 조회조건
//-------------------------------------------------------------------------
scwin.f_dsOrderSearchHeader = function () {
    ds_orderSearch.insertRow(0);
    ds_orderSearch.setRowPosition(0);
};

//-------------------------------------------------------------------------
// 청구 거래처 조회 조건 SET
//-------------------------------------------------------------------------
scwin.f_dsOrderQueryConditionHeader = function () {
    dma_orderQueryCondition.set("bizDivCntrYn", scwin.bizDivCntrYn);
    dma_orderQueryCondition.set("bizDivBulkYn", scwin.bizDivBulkYn);
    dma_orderQueryCondition.set("bizDivTplYn", scwin.bizDivTplYn);
};

//-------------------------------------------------------------------------
// 물류점소 영업부서 조회 조건 SET
//-------------------------------------------------------------------------
scwin.f_dsLobranQueryConditionHeader = function () {
    dma_lobranQueryCondition.set("lobranCd", scwin.lobranCd);
    dma_lobranQueryCondition.set("lobranClsCd", "T");
    dma_lobranQueryCondition.set("deptmentCd", DsConstants.SALES_DEPARTMENT); // 영업부서
    dma_lobranQueryCondition.set("useYn", DsConstants.YN_YES);
};

//-------------------------------------------------------------------------
// 계약거래처 DataSet을 초기화
//-------------------------------------------------------------------------
scwin.f_clearDataSetRetrieveCtrtClnt = function () {
    dma_retrieveCtrtClnt.set("ctrtClntNo", "");
    dma_retrieveCtrtClnt.set("bizDivCntrYn", scwin.bizDivCntrYn);
    dma_retrieveCtrtClnt.set("bizDivBulkYn", scwin.bizDivBulkYn);
    dma_retrieveCtrtClnt.set("bizDivTplYn", scwin.bizDivTplYn);
    dma_retrieveCtrtClnt.set("impExpDomesticClsCd", DsConstants.DOMESTIC_CD);
};

//-------------------------------------------------------------------------
// Data 초기화 (HTML INPUT)
//-------------------------------------------------------------------------
scwin.f_clearData = function () {
    // Order Master DataSet 값 초기화 -> TOBE에서 number값도 0으로 초기화 안되고 빈값으로 되어 해당 로직 주석처리
    // for (var i = 0; i < ds_order.getTotalCol(); i++) {
    //     ds_order.setCellData(ds_order.getRowPosition(), ds_order.getColumnID(i), "");
    // }

    ed_bilgLodeptNm.setValue("");
    ed_sellLodeptNm.setValue("");
    ed_dptWrkPlNm.setValue("");
    ed_arvWrkPlNm.setValue("");

    ed_dptWrkPlNm.hidVal = "";
    ed_arvWrkPlNm.hidVal = "";

    hid_odrKndCd.setValue(acb_odrKndCd.getValue()); // 오더종류
    hid_selfClsCd.setValue(DsConstants.SELF_CLS_CD_MCOM_TRANS); // 자가구분코드 - 벌크오더(당사운송:LI)

    scwin.hid_bizDivCntrYn = scwin.bizDivCntrYn; // 사업부문컨테이너여부
    scwin.hid_bizDivBulkYn = scwin.bizDivBulkYn; // 사업부문벌크여부
    scwin.hid_bizDivTplYn = scwin.bizDivTplYn; // 사업부문3자물류여부
    hid_sellYn.setValue(DsConstants.YN_YES); // 매출여부
    hid_cntrDsgYn.setValue(DsConstants.YN_NO); // 컨테이너지정여부
    hid_transCargoClsCd.setValue(DsConstants.ODR_BULK); // 운송화물구분코드
    hid_impExpDomesticClsCd.setValue(ds_odrKndCd.getCellData(acb_odrKndCd.getSelectedIndex(), "fltrCd2")); // 수출입내수구분코드    

    hid_odrClsCd.setValue(DsConstants.YN_NO); // 오더구분코드
    hid_smsSndYn.setValue(DsConstants.YN_NO); // SMS전송여부
    hid_odrDcsnYn.setValue(DsConstants.YN_NO); // 오더확정여부
    hid_odrCnclYn.setValue(DsConstants.YN_NO); // 오더취소여부
    hid_odrCompleteYn.setValue(DsConstants.YN_NO); // 오더완료여부
    hid_regBranCd.setValue(scwin.lobranCd); // 등록점소 - 사용자 설정 물류점소

    hid_salesPicNm.setValue(""); // 영업담당자명
    hid_salesPicTelNo.setValue(""); // 영업담당자 전화번호
    hid_tplPgmId.setValue(""); // 영업담당자 전화번호

    // EMEDIT 팝업 확인을 위한 HIDDEN 초기화
    scwin.hid_chkCtrtClntNo = ""; // 계약처
    scwin.hid_chkReqClntNo = ""; // 요청처
    scwin.hid_chkBilgClntNo = ""; // 청구처
    scwin.hid_chkRealMchtClntNo = ""; // 실화주
    scwin.hid_chkDmndNo = ""; // 수요가
    scwin.hid_chkSellLodeptCd = ""; // 매출부서
    scwin.hid_chkBilgLodeptCd = ""; // 청구부서
    scwin.hid_chkLineCd = ""; // LINE
    scwin.hid_chkBlNo = ""; // B/L 번호
    scwin.hid_chkCvsslMgntNo = ""; // 본선관리번호
    scwin.hid_chkDptWrkPlCd = ""; // 출발작업장
    scwin.hid_chkArvWrkPlCd = ""; // 도착작업장
    scwin.hid_ctrtNo = "";
    //scwin.hid_chkReterieve = ""; // 조회 성공여부 초기값
};

//-------------------------------------------------------------------------
// DataSet 초기화 처리 : 전체 DataSet 을 초기화 한다.
//-------------------------------------------------------------------------
scwin.f_clearDataSetAll = function () {

    // 오더기본정보 DataSet 초기화
    ds_order.setJSON([]);
    ds_order.insertRow(0);
    ds_order.setRowPosition(0);

    ds_shipmentIndicationOrder.setJSON([]);
    ds_shipmentIndicationCommodity.setJSON([]);

    // 계약 거래처 정보 (ds_retrieveCtrtClnt) DataSet 초기화
    scwin.f_clearDataSetRetrieveCtrtClnt();

    // 계약번호 (ds_ctrtNo) DataSet 초기화
    ds_ctrtNo.setJSON([]);

    // 요청 거래처 정보 (ds_reqClntNo) DataSet 초기화
    ds_reqClntNo.setJSON([]);

    // 청구 거래처 정보 (ds_bilgClntNo) DataSet 초기화
    ds_bilgClntNo.setJSON([]);

    // HIDDEN 값 초기화
    scwin.f_clearData();
}

//-------------------------------------------------------------------------
// DataSet 초기화 처리 : 요청거래처, 실화주, 청구거래처 DataSet 을 초기화 한다.
//-------------------------------------------------------------------------
scwin.f_clearClntDataSet = function () {
    ds_reqClntNo.setJSON([]);  // 요청거래처
    ds_bilgClntNo.setJSON([]); // 청구거래처

    ed_reqClntNo.setValue("");
    ed_bilgClntNo.setValue("");

    scwin.hid_ctrtNo = "";
};

//-------------------------------------------------------------------------
// 오더종류 초기화 처리 : 오더종류를 초기화 한다.
//-------------------------------------------------------------------------
scwin.f_defaultOdrKndSetting = function () {
    // 오더종류 설정 - default : 수입본선벌크오더
    // 오더종류 설정 - default : 내수운송공장내
    // var odrKndCd = $p.parent().$c.gus.getMapValue("ODR_KND_CD");
    // if ($c.gus.cfIsNull(odrKndCd)) odrKndCd = DsConstants.ODR_KND_CD_DOMESTIC_BASE_INSIDE_ODR;
    var odrKndCd = DsConstants.ODR_KND_CD_DOMESTIC_BASE_INSIDE_ODR;

    acb_odrKndCd.setValue(odrKndCd);

    scwin.f_setDisplayOdrKndCd(acb_odrKndCd.getValue());

    hid_odrKndCd.setValue(acb_odrKndCd.getValue());
    hid_transCargoClsCd.setValue(ds_odrKndCd.getCellData(acb_odrKndCd.getSelectedIndex(), "fltrCd1"));
    hid_impExpDomesticClsCd.setValue(ds_odrKndCd.getCellData(acb_odrKndCd.getSelectedIndex(), "fltrCd2"));
    hid_selfClsCd.setValue(DsConstants.SELF_CLS_CD_MCOM_TRANS); // 자가구분코드 - 벌크오더(당사운송:LI)
};

//-------------------------------------------------------------------------
// 선택된 오더 유형별 화면 설정을 변경한다.
//-------------------------------------------------------------------------
scwin.f_setDisplayOdrKndCd = function (odrKndCd) {

    switch (odrKndCd) {
        case DsConstants.ODR_KND_CD_DOMESTIC_BASE_INSIDE_ODR: // 내수 거점내 오더
        case DsConstants.ODR_KND_CD_DOMESTIC_BASE_OUTSIDE_ODR: // 내수 거점간 오더
        case DsConstants.ODR_KND_CD_DOMESTIC_FCTY_CRRYOUT_ODR: // 내수 공장반출 오더
        case DsConstants.ODR_KND_CD_DOMESTIC_LOGIS_BASE_CRRYOUT_ODR: // 내수 물류기지반출 오더
        case DsConstants.ODR_KND_CD_DOMESTIC_BASE_INSIDE_RETRV_ODR: // 내수 거점간회수 오더
        case DsConstants.ODR_KND_CD_DOMESTIC_FCTY_OUTSIDE_RETRV_ODR: // 내수 공장회수 오더
        case DsConstants.ODR_KND_CD_DOMESTIC_LOGIS_BASE_RETRV_ODR: // 내수 물류기지회수 오더
        case DsConstants.ODR_KND_CD_DOMESTIC_LDULD_ODR: // 내수 상하차 오더
        case DsConstants.ODR_KND_CD_DOMESTIC_STR_ODR: // 내수 보관 오더
        case DsConstants.ODR_KND_CD_PIER_WAGES_ODR: // 부두노임 오더
        case DsConstants.ODR_KND_CD_PIER_YARD_WAGES_ODR: // 부두 장치장 노임 오더
        case DsConstants.ODR_KND_CD_COMMON_USE_YARD_WAGES_ODR: // 상용 장치장 노임 오더
        case DsConstants.ODR_KND_CD_MONTH_PUBLIC_CHARGES_WAGES_ODR: // 월 제세공과성 노임 오더
        case DsConstants.ODR_KND_CD_PACK_ODR: // 포장 오더
            scwin.cf_ShowObject([tbx_dmndNo_01, udc_dmndNo]); // 수요가
            scwin.cf_ShowObject([tr_picNm_picTelNo]); // 상차담당, 하차담당, 오더담당
            scwin.cf_ShowObject([grp_arvWrkPlCd]); // 도착작업장
            scwin.cf_ShowObject([tbx_wrkStDtHh_01, grp_wrkStDtHh_02]); // 출발일자, 출발시간
            scwin.cf_ShowObject([tbx_wrkEndDtHh_01, grp_wrkEndDtHh_02]); // 도착일자, 도착시간           

            // Vaildation 확인용 Object 설정
            scwin.vaildObj = new Array(acb_odrKndCd
