//-------------------------------------------------------------------------
// 팝업 처리시 검색된 데이터인 경우 팝업 처리 안함.
//-------------------------------------------------------------------------
scwin.f_chkOpenCommonPopUp = function (inObj, pairObj, disGubun, isCode) {

    // 값이 입력이 안된 경우, 해당 Text Box가 readonly 인 경우, 이전값과 동일한 경우 팝업을 실행하지 않음.
    //alert(cfCanOpenPopup(inObj, pairObj) + "/" + inObj.hidVal + "/" + pairObj.hidVal);
    if (!$c.gus.cfCanOpenPopup(inObj, pairObj))
        return;

    // 짝이 되는 오브젝트의 값 제거
    $c.gus.cfClearPairObj(pairObj);

    // 검색어 세팅
    var pVal = $c.gus.cfGetValue(inObj);

    // inObj가 코드 필드일 경우 팝업
    if (isCode == null || isCode == true)
        scwin.f_openCommonPopUp(disGubun, pVal, '', 'T', 'T');
    // inObj가 코드명 필드일 경우 팝업
    else
        scwin.f_openCommonPopUp(disGubun, '', pVal, 'T', 'T');
}

//-------------------------------------------------------------------------
// PopUp 이미지를 활성화 시킨다. 
//-------------------------------------------------------------------------
scwin.f_EnablePopUpObj = function () {
    $c.gus.cfEnableObjects([btn_PopUp1, btn_PopUp2, btn_PopUp3, btn_PopUp4, btn_PopUp5, btn_PopUp6, btn_PopUp7, btn_PopUp8]);
}

//-------------------------------------------------------------------------
// PopUp 이미지를 비활성화 시킨다. 
//-------------------------------------------------------------------------
scwin.f_DisablePopUpObj = function () {
    $c.gus.cfDisableObjects([btn_PopUp1, btn_PopUp2, btn_PopUp3, btn_PopUp4, btn_PopUp5, btn_PopUp6, btn_PopUp7, btn_PopUp8]);
}

//-------------------------------------------------------------------------
//시작시간, 종료시간 유효성 체크 - 동일한 경우 포함
//-------------------------------------------------------------------------
scwin.f_chkTime = function (strDate, strTime, endDate, endTime) {
    var differTime = (endDate + endTime) - (strDate + strTime);

    if (differTime >= 0) { return true; }
    else { return false; }
}

//-------------------------------------------------------------------------
//시작시간, 종료시간 유효성 체크 - 동일한 경우 오류
//-------------------------------------------------------------------------
scwin.f_chkTimeNotEqual = function (strDate, strTime, endDate, endTime) {
    var differTime = (endDate + endTime) - (strDate + strTime);

    if (differTime > 0) { return true; }
    else { return false; }
}

//-------------------------------------------------------------------------
// 조회
//-------------------------------------------------------------------------
scwin.f_Retrieve = function () {
    var clntNo = ed_clntNo.getValue().replace(/\s*$/, '');
    var mchtOdrKndCd = acb_mchtOdrKndCd.getValue();
    var mchtOdrNo = ed_mchtOdrNo.getValue().replace(/\s*$/, '');
    var mcomOdrNo = ed_mcomOdrNo.getValue().replace(/\s*$/, '');

    //20171221 kpx logseq 관련 추가
    ds_orderSearch.setCellData(0, "logSeq", scwin.hid_logSeq);

    if ($c.gus.cfIsNull(mcomOdrNo)) {
        if (!$c.gus.cfIsNull(clntNo)) { // 계약거래처가 지정된 경우
            if ($c.gus.cfIsNull(mchtOdrKndCd)) {
                $c.gus.cfAlertMsg(MSG_CM_ERR_002, new Array("화주오더종류"));
                acb_mchtOdrKndCd.focus();
                return;
            }

            if ($c.gus.cfIsNull(mchtOdrNo)) {
                $c.gus.cfAlertMsg(MSG_CM_ERR_002, new Array("화주오더번호"));
                ed_mchtOdrNo.focus();
                return;
            }
        } else {
            $c.gus.cfAlertMsg(MSG_CM_ERR_002, new Array("계약거래처 또는 당사오더번호"));
            ed_clntNo.focus();
            return;
        }
    } else {
        if (!$c.gus.cfValidate(ed_mcomOdrNo)) {
            return;
        }
    }

    // DataSet 초기화
    scwin.f_clearDataSetAll();

    ds_orderSearch.setCellData(0, "repClntNo", scwin.hid_ctrtRepClntNo);
    ds_orderSearch.setCellData(0, "docCd", scwin.hid_docCd);
    ds_orderSearch.setCellData(0, "wrkPlCd", scwin.hid_wrkPlCd);
    ds_orderSearch.setCellData(0, "itemCd", scwin.hid_itemCd);
    ds_orderSearch.setCellData(0, "osideCd", scwin.hid_osideCd);
    ds_orderSearch.setCellData(0, "logSeq", scwin.hid_logSeq);
    ds_orderSearch.setCellData(0, "logSeq", "0");

    $c.sbm.execute(sbm_reterieve);
};

//-------------------------------------------------------------------------
// 수정
//-------------------------------------------------------------------------
scwin.f_Update = function () {
    $c.gus.cfEnableKeyData();
    $c.gus.cfDisableKey();
    $c.gus.cfDisableAllBtn();
    $c.gus.cfEnableObjects([btn_save, btn_delete]);
    gr_shipmentIndicationCommodityList.setReadOnly("grid", false);
    scwin.hid_odrJobType == DGauceConstants.TB_JOB_UPDATE;

    // PopUp 이미지 버튼을 활성화 시킨다.
    scwin.f_EnablePopUpObj();

    $c.gus.cfEnableObjects([tbl_order]);
    $c.gus.cfDisableObjects([acb_odrKndCd, lc_ctrtNo]);

    if (hid_odrWrkPathCnt.getValue() > 0 && hid_odrWrkPathCnt.getValue() == ds_orderCommodity.getRowCount() && hid_odrDcsnYn.getValue() != DsConstants.YN_YES && hid_odrDelYn.getValue() != DsConstants.YN_YES) {
        // 오더 확정 버튼 활성화
        $c.gus.cfEnableObjects([btn_confirmOrder]);
    }

    // 실적 발생여부를 조회하여 수정항목을 설정한다.
    if (scwin.f_chkResultsConfirmation()) {
        // 수정불가 항목을 Disable 한다.
        // 수정 불가항목 : 오더번호, 오더종류, 계약거래처, 계약번호, 대표거래처
        // , 출발작업장, 도착작업장, 작업시작일자, 작업시작시간, 작업종료일자, 작업종료시간
        // , 자가구분, 작업유형, 합적여부 (벌크오더 화면에는 해당되지 않는다.
        $c.gus.cfDisableObjects([ed_dptWrkPlCd, ed_dptWrkPlNm, ed_arvWrkPlCd, ed_arvWrkPlNm, ica_wrkStDt, ed_wrkStHh, ica_wrkEndDt, ed_wrkEndHh, acb_wrkPatternCd, rd_coshippingYn]);
    }
}

//-------------------------------------------------------------------------
// 저장
//-------------------------------------------------------------------------
scwin.f_Save = async function () {
    // 대표 거래처 정보 설정
    if ($c.gus.cfIsNull(hid_repClntNo.getValue()))
        hid_repClntNo.setValue(scwin.hid_ctrtRepClntNo);

    // 작업구분에 따른 확인
    if (scwin.hid_odrJobType == DGauceConstants.TB_JOB_INSERT) {
        // INSERT
        if (ds_order.getModifiedIndex().length == 0) {
            $c.gus.cfAlertMsg(MSG_CM_ERR_001, new Array("오더기본정보"));
            return false;
        }

        if (ds_orderCommodity.getModifiedIndex().length == 0) {
            $c.gus.cfAlertMsg(MSG_CM_ERR_001, new Array("오더품목정보"));
            return false;
        }

        /*20160126 화물위탁증 관련 추가*/
        ds_order.setCellData(0, "trnsRealMchtClntNm", "KPX케미칼(주)");
        ds_order.setCellData(0, "trnsRealMchtClntTelNo", "052-279-0266");

        //20180201 오창영대리 요청
        for (var i = 0; i < ds_orderCommodity.getRowCount(); i++) {
            //grid의 데이터를 집어넣기
            ds_orderCommodity.setCellData(i, "grossWt", ds_shipmentIndicationCommodity.getCellData(i, "wt"));
        }

        $c.sbm.setAction(sbm_save, "/ncall.ds.sd.odrmgnt.odrreg.RegistShipmentIndicationOrderRequestCMD.do");

        // 오더요청 기본정보 Update 설정
        var v_logSeq = ds_shipmentIndicationOrder.getCellData(ds_shipmentIndicationOrder.getRowPosition(), "logSeq");
        for (var i = 0; i < ds_shipmentIndicationOrder.getRowCount(); i++) {
            if (v_logSeq >= ds_shipmentIndicationOrder.getCellData(i, "logSeq")) {
                ds_shipmentIndicationOrder.setCellData(i, "rowStatus", DGauceConstants.TB_JOB_UPDATE);
                ds_shipmentIndicationOrder.setCellData(i, "wrkStDt", ica_wrkStDt.getValue()); // 출발일자 설정
                ds_shipmentIndicationOrder.setCellData(i, "wrkStHh", ed_wrkStHh.getValue()); // 출발시간 설정
                ds_shipmentIndicationOrder.setCellData(i, "wrkEndDt", ica_wrkEndDt.getValue()); // 도착일자 설정
                ds_shipmentIndicationOrder.setCellData(i, "wrkEndHh", ed_wrkEndHh.getValue()); // 도착시간 설정
            } else {
                break;
            }

            // 출발작업장코드 자동 설정
            if ($c.gus.cfIsNull(ds_orderCommodity.getCellData(i, "dptWrkPlCd").trim()))
                ds_orderCommodity.setCellData(i, "dptWrkPlCd", ed_dptWrkPlCd.getValue().trim());

            // 도착작업장코드 자동 설정
            if ($c.gus.cfIsNull(ds_orderCommodity.getCellData(i, "arvWrkPlCd").trim()))
                ds_orderCommodity.setCellData(i, "arvWrkPlCd", ed_arvWrkPlCd.getValue().trim());

        }

        // 품명 1건인 경우 합적할수 없습니다.
        if (ds_orderCommodity.getRowCount() == 1 && rd_coshippingYn.getValue() == "1") {
            $c.gus.cfAlertMsg(MSG_CM_ERR_041, new Array("오더품목정보가 1건인 경우", "합적"));
            return false;
        }

        ds_order.setCellData(0, "ctrtNo", lc_ctrtNo.getValue());
        ds_order.setCellData(0, "ctrtWrkPathSeq", "1");

        ds_order.modifyAllStatus("C");
        ds_orderCommodity.modifyAllStatus("C");
        //ds_shipmentIndicationOrder.modifyAllStatus("C");

    } else {
        // UPDATE
        if (ds_order.getModifiedIndex().length == 0 && ds_orderCommodity.getModifiedIndex().length == 0) {
            $c.gus.cfAlertMsg(MSG_CM_ERR_001, new Array("오더정보"));
            return false;
        }

        $c.sbm.setAction(sbm_save, "/ncall.ds.sd.odrmgnt.odrreg.UpdateShipmentIndicationOrderRequestCMD.do");

        // 오더요청 정보 Update 설정
        var v_logSeq = ds_shipmentIndicationOrder.getCellData(ds_shipmentIndicationOrder.getRowPosition(), "logSeq");
        for (var i = 0; i < ds_shipmentIndicationOrder.getRowCount(); i++) {
            if (v_logSeq >= ds_shipmentIndicationOrder.getCellData(i, "logSeq")) {
                if (v_logSeq == ds_shipmentIndicationOrder.getCellData(i, "logSeq")) {
                    ds_shipmentIndicationOrder.setCellData(i, "rowStatus", DGauceConstants.TB_JOB_UPDATE);
                } else if (!$c.gus.cfIsNull(ds_shipmentIndicationOrder.getCellData(i, "mcomOdrNo"))) {
                    //ds_shipmentIndicationOrder.getCellData(i, "rowStatus") = DGauceConstants.TB_JOB_UPDATE;          
                } else {
                    await $c.gus.cfAlertMsg("이전 오더요청 오더에 대한 작업이 진행되지 않았습니다.");
                    ds_shipmentIndicationOrder.setRowPosition(i);
                    return false;
                }
            } else {
                break;
            }
        }

        // 품명 정보 변경 내역 - 확인
        for (j = 0; j < ds_orderCommodity.getRowCount(); j++) {
            ds_orderCommodity.setCellData(j, "rmk", ds_orderCommodity.getCellData(j, "rmk") + " ");
            // 출발일자/시간, 도착일자/시간 변경시 품명 작업시작일자/시간, 작업완료일자/시간 설정
            if (ds_order.getCellData(ds_order.getRowPosition(), "wrkStDt") != ds_order.getOriginalCellData(ds_order.getRowPosition(), "wrkStDt")
                || ds_order.getCellData(ds_order.getRowPosition(), "wrkStHh") != ds_order.getOriginalCellData(ds_order.getRowPosition(), "wrkStHh")
                || ds_order.getCellData(ds_order.getRowPosition(), "wrkEndDt") != ds_order.getOriginalCellData(ds_order.getRowPosition(), "wrkEndDt")
                || ds_order.getCellData(ds_order.getRowPosition(), "wrkEndHh") != ds_order.getOriginalCellData(ds_order.getRowPosition(), "wrkEndHh")) {

                // 품명 데이터 셋에서 해당 품명을 찾아 정보를 변경
                ds_orderCommodity.setCellData(j, "wrkStDt", ica_wrkStDt.getValue()); // 작업시작일자
                ds_orderCommodity.setCellData(j, "wrkStHh", ed_wrkStHh.getValue()); // 작업시작시간
                ds_orderCommodity.setCellData(j, "wrkEndDt", ica_wrkEndDt.getValue()); // 작업종료일자
                ds_orderCommodity.setCellData(j, "wrkEndHh", ed_wrkEndHh.getValue()); // 작업종료시간
            }

            // 출발지 정보 변경시 오더품명 출발지 정보 변경
            if (ds_order.getCellData(ds_order.getRowPosition(), "dptWrkPlCd") != ds_order.getOriginalCellData(ds_order.getRowPosition(), "dptWrkPlCd")) {
                // 출발작업장코드 자동 설정
                if ($c.gus.cfIsNull(ds_orderCommodity.getCellData(j, "dptWrkPlCd").trim()))
                    ds_orderCommodity.setCellData(j, "dptWrkPlCd", ed_dptWrkPlCd.getValue().trim());
            }

            // 도착지 정보 변경시 오더품명 도착지 정보 변경
            if (ds_order.getCellData(ds_order.getRowPosition(), "arvWrkPlCd") != ds_order.getOriginalCellData(ds_order.getRowPosition(), "arvWrkPlCd")) {
                // 도착작업장코드 자동 설정
                if ($c.gus.cfIsNull(ds_orderCommodity.getCellData(j, "arvWrkPlCd").trim()))
                    ds_orderCommodity.setCellData(j, "arvWrkPlCd", ed_arvWrkPlCd.getValue().trim());
            }
        }
    }

    let retChk = "";
    for (var i = 0; i < ds_shipmentIndicationCommodity.getRowCount(); i++) {
        retChk = await scwin.f_tplCommCdChk(i);
        if (retChk) {
            return;
        }
    }

    // 작업경로 선택 사항 확인
    if (ds_shipmentIndicationCommodity.getRowCount() > 0) {
        var ctrtWrkPathSeq = 0;
        for (var i = 0; i < ds_shipmentIndicationCommodity.getRowCount(); i++) {
            if (ds_shipmentIndicationCommodity.getCellData(i, "ctrtWrkPathSeq") > 0) {
                ctrtWrkPathSeq = ds_shipmentIndicationCommodity.getCellData(i, "ctrtWrkPathSeq");
                break;
            }
        }

        if (ctrtWrkPathSeq == 0) {
            $c.gus.cfAlertMsg(MSG_CM_WRN_007, new Array("작업경로"));
            return;
        }
        else {
            for (var idx = 0; idx < ds_shipmentIndicationCommodity.getRowCount(); idx++) {
                ds_shipmentIndicationCommodity.setCellData(idx, "ctrtWrkPathSeq", ctrtWrkPathSeq);
            }
        }

        for (var idx = 0; idx < ds_shipmentIndicationCommodity.getRowCount(); idx++) {
            for (var commIdx = 0; commIdx < ds_orderCommodity.getRowCount(); commIdx++) {
                if (ds_orderCommodity.getCellData(commIdx, "mgntSeq") == ds_shipmentIndicationCommodity.getCellData(idx, "mgntSeq")) {
                    ds_orderCommodity.setCellData(commIdx, "ctrtWrkPathSeq", ds_shipmentIndicationCommodity.getCellData(idx, "ctrtWrkPathSeq")); // 계약작업경로순번
                    ds_orderCommodity.setCellData(commIdx, "ctrtWrkPathNm", ds_shipmentIndicationCommodity.getCellData(idx, "ctrtWrkPathNm")); // 계약작업경로
                }
            }
        }
    }

    /* 만약에 계약작업경로가 0으로 남아 있는지 여부 확인하여 1번품명의 계약작업경로로 셋팅 */
    for (var ctrtidx = 0; ctrtidx < ds_orderCommodity.getRowCount(); ctrtidx++) {
        if (ds_orderCommodity.getCellData(ctrtidx, "ctrtWrkPathSeq") == 0) {
            ds_orderCommodity.setCellData(ctrtidx, "ctrtWrkPathSeq", ds_shipmentIndicationCommodity.getCellData(0, "ctrtWrkPathSeq")); // 계약작업경로순번
            ds_orderCommodity.setCellData(ctrtidx, "ctrtWrkPathNm", ds_shipmentIndicationCommodity.getCellData(0, "ctrtWrkPathNm")); // 계약작업경로
        }
    }

    // 필수 입력사항을 체크
    if (await scwin.f_validChk()) {
        // 삭제 시에 귀책사유 선택 여부 확인
        if (tbx_stsClsCd.getValue() == "D" && acb_odrCnclItemCd.getValue() == "") {
            $c.win.alert("귀책사유를 선택해 주십시요.");
            return;
        }

        //let ret = await $c.win.confirm(MSG_CM_CRM_001, new Array("오더정보"));
        let ret = await $c.win.confirm(MSG_CM_CRM_001);
        if (ret) {
            //Eidt 속성을 Disable로 변경한다.
            $c.gus.cfDisableKeyData();
            $c.gus.cfDisableAllBtn();

            $c.sbm.execute(sbm_save);
        }
    }
}

//-------------------------------------------------------------------------
// 자재마스터 상위 존재여부 체크
//-------------------------------------------------------------------------
scwin.f_tplCommCdChk = async function (row) {
    var clntNo = ds_shipmentIndicationOrder.getCellData(0, "repClntNo");
    var clntCommCd = ds_shipmentIndicationCommodity.getCellData(row, "clntCommCd");

    if (clntNo.trim().length == 0) {
        return;
    }
    if (clntCommCd.trim().length == 0) {
        return;
    }

    /*
    * 1) pSelectID : XML상의 SELECT ID NotNull "retrieveClntInfo"
    * 2) pCode : 화면에서의 ??? Code Element의 Value null "1234"
    * 3) pName : 화면에서의 ??? Name Element의 Value null "동부"
    * 4) pWinCloseTF : 결과가 1건 일때 원도우를 AutoClose 여부 (T:Close,F:Opened) null(F) "T","F"
    * 5) pDispCnt : 검색 결과 컬럼의 보여주는 개수 (SELECT절의 순서) MAX:10 null(2) "5"
    * 6) pTitle : Title명's null "100,200"
    * 7) pWidth : 보여주는 각 컬럼들의 폭 null "100,200"
    * 8) pHidden : 컬럼중에서 숨기는 컬럼 지정 null "7,8,9,10"
    * 9) pWhere : SQL절의 WHERE절에 원하는 조건을 선택함 MAX:12개까지 가능 null "SHIP"
    * 10) pW : POP-UP뛰을때 원도우의 사용자 정의 폭 null "500"
    * 11) pH : POP-UP뛰을때 우도우의 사용자 정의 높이 null "600"
    * 12) pTop : 윈도우 위치 Y좌표 null "10"
    * 13) pLeft : 윈도우 위치 X좌표 null "10"
    * 14) pExistTF : 중복체크여부 null "F"
    * 15) pAllSearchTF : 전체검색허용여부 null "F" -- retrieveTplCommCd 는 무조건 허용
    * 16) pWtitleSearch : POP-UP Window Title 검색어1,2(각화면에서 변경할경우) null "Win타이틀,검색어1,검색어2"
    * 17) pNoDataCloseTF : Data건수가 0건일때 Window를 뛰우지 않음 리턴:"N/A" null "F"
    */
    udc_comCode1.setSelectId("retrieveTplCommCd"); // XML상의 SELECT ID
    let rtnList = await udc_comCode1.cfCommonPopUpAsync(scwin.udc_tplCommCdChk_callBackFunc // 콜백 함수
        , "사용안함"
        , "사용안함"
        , "T"
        , null
        , null
        , null
        , null
        , clntNo + "," + clntCommCd
        , null
        , null
        , null
        , null
        , null
        , "F" //null
        , null
        , null//"T"
    ); // 거래처

    if (rtnList[0] == '0') { //자재번호가 존재하지 않을경우
        $c.win.alert("자재번호 : " + clntCommCd + " 은(는) 존재하지 않습니다.<br/><br/>관리자에게 문의하여 주십시오.");
        return true;
    } else if (rtnList[0] == '1') { //자재번호 존재하지만 상위코드 없는경우
        $c.win.alert("자재번호 : " + clntCommCd + " 은(는) 자재마스터 상위코드가 없습니다.<br/><br/>\'확인\' 버튼을 누르면 등록팝업이 뜹니다.<br/><br/>등록해 주십시오.");
        return true;
    } else if (rtnList[0] == '2') { //정상일 경우
        return false;
    } else {
        $c.win.alert("더이상 진행할 수 없읍니다. 관리자에게 문의 하십시오.");
        return true;
    }
};

