//-------------------------------------------------------------------------
// 저장전 validation check - 오더 정보
//-------------------------------------------------------------------------
scwin.f_validChk = async function () {
    let ret = await $c.gus.cfValidate(scwin.vaildObj)
    if (ret) {

        if (grp_wrkEndDtHh_02.getStyle("display") != "none") {
            // 출발일자, 도착일자 확인

            // 출발작업일자가 도착작업일자보다 큰 경우
            if (ica_wrkStDt.getValue().trim() > ica_wrkEndDt.getValue().trim()) {
                $c.gus.cfAlertMsg(MSG_CM_ERR_048, new Array("출발작업일자", "도착작업일자"));
                ica_wrkEndDt.focus();
                return false;
            }

            // 출발작업시간이 도착작업시간보다 큰 경우
            if (ica_wrkStDt.getValue().trim() == ica_wrkEndDt.getValue().trim() && ed_wrkStHh.getValue().trim() >= ed_wrkEndHh.getValue().trim()) {
                $c.gus.cfAlertMsg(MSG_CM_ERR_057, new Array("도착작업시간", "출발작업시간"));
                ed_wrkEndHh.focus();
                return false;
            }

        }

        // 상차, 하차, 오더 담당 전화번호 유효성 확인
        if (tr_picNm_picTelNo.getStyle("display") != "none") {
            if (ed_onPicTelNo.getValue().trim() != "" && !dscommon.cf_PhoneCheck(ed_onPicTelNo))
                return false;

            if (ed_offPicTelNo.getValue().trim() != "" && !dscommon.cf_PhoneCheck(ed_offPicTelNo))
                return false;

            if (ed_odrPicTelNo.getValue().trim() != "" && !dscommon.cf_PhoneCheck(ed_odrPicTelNo))
                return false;
        }

        for (var i = 0; i < ds_orderCommodity.getRowCount(); i++) {
            // 수량, 중량, CBM 중 한가지는 입력하여야 합니다.
            if (ds_orderCommodity.getCellData(i, "qty") == 0
                && ds_orderCommodity.getCellData(i, "grossWt") == 0
                && ds_orderCommodity.getCellData(i, "cbm") == 0) {

                $c.gus.cfAlertMsg("수량, 중량, CBM 중 한가지는 입력하셔야 합니다.");
                ds_orderCommodity.setRowPosition(i);
                //gr_orderCommodity.SetColumn("qty"); TOBE : 해당 그리드 없음
                return false;
            }

            // 품명의 출발일자, 출발시간, 도착일자, 도착시간 정보를 오더 출발일시, 도착일시로 설정한다.
            ds_orderCommodity.setCellData(i, "wrkStDt", ica_wrkStDt.getValue());
            ds_orderCommodity.setCellData(i, "wrkStHh", ed_wrkStHh.getValue());
            ds_orderCommodity.setCellData(i, "wrkEndDt", ica_wrkEndDt.getValue());
            ds_orderCommodity.setCellData(i, "wrkEndHh", ed_wrkEndHh.getValue());

            // 출발작업장코드, 도착작업장코드 자동 설정
            ds_orderCommodity.setCellData(i, "dptWrkPlCd", ed_dptWrkPlCd.getValue().trim());
            ds_orderCommodity.setCellData(i, "arvWrkPlCd", ed_arvWrkPlCd.getValue().trim());

            // 필수 항목 확인 - 품명 정보 설정 확인
            if ($c.gus.cfIsNull(ds_orderCommodity.getCellData(i, "commCd"))) {
                $c.gus.cfAlertMsg(MSG_CM_WRN_018, new Array("품명", "EDI MAPPING 정보"));
                return false;
            }
        }

        return true;
    } else {
        return false;
    }
}

//-------------------------------------------------------------------------
// 오더요청 정보를 오더 정보에 설정
//-------------------------------------------------------------------------
scwin.f_setOrderInformation = function (jobType) {
    if ($c.gus.cfIsNull(jobType)) return; // jobType 이 설정되지 않은 경우
    if (ds_shipmentIndicationOrder.getRowCount() == 0) return; // 오더요청 정보가 존재하지 않는 경우

    switch (jobType) {
        case DGauceConstants.TB_JOB_INSERT: // INSERT
            // 오더 정보 설정
            if (ds_shipmentIndicationOrder.getRowCount() > 0 && ds_order.getRowCount() == 0) {
                var s_row = ds_shipmentIndicationOrder.getRowPosition();

                // 오더 정보가 존재하지 않는 경우 오더 정보 추가
                ds_order.setJSON([]);
                ds_order.insertRow(0);
                ds_order.setRowPosition(0)
                scwin.f_clearData();

                if (ds_ctrtNo.getRowCount() == 0) { // 계약번호 조회
                    hid_ctrtClntNo.setValue(ds_shipmentIndicationOrder.getCellData(s_row, "clntNo"));

                    dma_retrieveCtrtClnt.set("ctrtClntNo", hid_ctrtClntNo.getValue());
                    dma_retrieveCtrtClnt.set("bizDivCntrYn", scwin.hid_bizDivCntrYn);
                    dma_retrieveCtrtClnt.set("bizDivBulkYn", scwin.hid_bizDivBulkYn);

                    $c.sbm.execute(sbm_retrieveCtrtClnt);                    
                }

                hid_ctrtClntNo.setValue(ds_shipmentIndicationOrder.getCellData(s_row, "clntNo")); // 계약거래처번호
                hid_ctrtClntNm.setValue(ds_shipmentIndicationOrder.getCellData(s_row, "clntNm")); // 계약거래처번호

                hid_clntMgntNo.setValue(ds_shipmentIndicationOrder.getCellData(s_row, "mchtOdrNo")); // 거래처관리번호 <- 화주오더번호

                // 회사코드 - 청구거래처 정보 설정
                if (ds_shipmentIndicationOrder.getRowCount() > 0) {
                    if (!$c.gus.cfIsNull(ds_shipmentIndicationOrder.getCellData(s_row, "coBilgClntNo").trim())) {
                        lc_bilgClntNm.setValue(ds_shipmentIndicationOrder.getCellData(s_row, "coBilgClntNo")); // 청구거래처
                    }
                }

                ed_dmndNo.setValue(ds_shipmentIndicationOrder.getCellData(s_row, "dmndNo")); // 고객 -> 수요가
                ed_dmndNo.hidVal = ds_shipmentIndicationOrder.getCellData(s_row, "dmndNo"); // 고객 -> 수요가
                ed_dmndNm.setValue(ds_shipmentIndicationOrder.getCellData(s_row, "dmndNm"));
                ed_dmndNm.hidVal = ds_shipmentIndicationOrder.getCellData(s_row, "dmndNm");
                hid_repClntNo.setValue(ds_shipmentIndicationOrder.getCellData(s_row, "repClntNo")); // 대표거래처번호

                if (!$c.gus.cfIsNull(ds_shipmentIndicationOrder.getCellData(s_row, "selfClsCd")))
                    hid_selfClsCd.setValue(ds_shipmentIndicationOrder.getCellData(s_row, "selfClsCd")); // 자가구분

                tbx_selfClsCd.setValue(hid_selfClsCd.getValue());  // 자가구분 - 표시

                // 정상 오더인경우
                ed_dptWrkPlCd.setValue(ds_shipmentIndicationOrder.getCellData(s_row, "bizWrkPlCd")); // 사업장 - > 출발작업장
                ed_dptWrkPlCd.hidVal = ds_shipmentIndicationOrder.getCellData(s_row, "bizWrkPlCd"); // 사업장 - > 출발작업장
                ed_dptWrkPlNm.setValue(ds_shipmentIndicationOrder.getCellData(s_row, "bizWrkPlNm"));
                ed_dptWrkPlNm.hidVal = ds_shipmentIndicationOrder.getCellData(s_row, "bizWrkPlNm");
                ed_arvWrkPlCd.setValue(ds_shipmentIndicationOrder.getCellData(s_row, "zipWrkPlCd")); // 우편번호 -> 도착작업장
                ed_arvWrkPlCd.hidVal = ds_shipmentIndicationOrder.getCellData(s_row, "zipWrkPlCd"); // 우편번호 -> 도착작업장
                ed_arvWrkPlNm.setValue(ds_shipmentIndicationOrder.getCellData(s_row, "zipWrkPlNm"));
                ed_arvWrkPlNm.hidVal = ds_shipmentIndicationOrder.getCellData(s_row, "zipWrkPlNm");

                ed_arvDtl.setValue(ds_shipmentIndicationOrder.getCellData(s_row, "dtlAddr1"));

                // 출발지(사업장), 도착지(우편번호) 작업장구분과 동일한 작업장 구분인 오더로 설정 - 자가구분설정시 자가구분확인             
                for (var i = 0; i < ds_odrKndCd.getRowCount(); i++) {
                    if (ds_shipmentIndicationOrder.getCellData(s_row, "selfClsCd") == "JO" || ds_shipmentIndicationOrder.getCellData(s_row, "selfClsCd") == "JI") {
                        if (ds_odrKndCd.getCellData(i, "dptWrkPlCls") == ds_shipmentIndicationOrder.getCellData(s_row, "bizWrkPlClsCd")
                            && ds_odrKndCd.getCellData(i, "arvWrkPlCls") == ds_shipmentIndicationOrder.getCellData(s_row, "zipWrkPlClsCd")
                            && ds_odrKndCd.getCellData(i, "selfClsCd") == ds_shipmentIndicationOrder.getCellData(s_row, "selfClsCd")) {
                            ds_odrKndCd.setRowPosition(i);
                            break;
                        }
                    } else {
                        if (ds_odrKndCd.getCellData(i, "dptWrkPlCls") == ds_shipmentIndicationOrder.getCellData(s_row, "bizWrkPlClsCd")
                            && ds_odrKndCd.getCellData(i, "arvWrkPlCls") == ds_shipmentIndicationOrder.getCellData(s_row, "zipWrkPlClsCd")) {
                            ds_odrKndCd.setRowPosition(i);
                            break;
                        }
                    }
                }

                ica_wrkEndDt.setValue(ds_shipmentIndicationOrder.getCellData(s_row, "arvIntendDt"));

                if (scwin.isTime(ds_shipmentIndicationOrder.getCellData(s_row, "arvIntendHh"))) {
                    ed_wrkEndHh.setValue(ds_shipmentIndicationOrder.getCellData(s_row, "arvIntendHh"));
                }

                hid_wrkPatternCd.setValue(ds_shipmentIndicationOrder.getCellData(s_row, "mchtOdrKndCd"));
                acb_wrkPatternCd.setValue(ds_shipmentIndicationOrder.getCellData(s_row, "mchtOdrKndCd"));

                ed_offPicNm.setValue(ds_shipmentIndicationOrder.getCellData(s_row, "accp"));
                ed_offPicTelNo.setValue(ds_shipmentIndicationOrder.getCellData(s_row, "tplTelNo")); // 전화번호

                if (scwin.isTime(ds_shipmentIndicationOrder.getCellData(s_row, "arvIntendHh"))) {
                    txt_rmk.setValue(ds_shipmentIndicationOrder.getCellData(s_row, "unqItm")); // 특이사항
                } else {
                    txt_rmk.setValue(ds_shipmentIndicationOrder.getCellData(s_row, "unqItm") + " / 가능한 빨리 처리바람. "); // 특이사항
                }
            } else if ($c.gus.cfIsNull(ds_order.getCellData(ds_order.getRowPosition(), "odrNo"))) {

                var s_row = ds_shipmentIndicationOrder.getRowPosition();

                if (ds_ctrtNo.getRowCount() == 0) { // 계약번호 조회
                    hid_ctrtClntNo.setValue(ds_shipmentIndicationOrder.getCellData(s_row, "clntNo"));

                    dma_retrieveCtrtClnt.set("ctrtClntNo", hid_ctrtClntNo.getValue());
                    dma_retrieveCtrtClnt.set("bizDivCntrYn", scwin.hid_bizDivCntrYn);
                    dma_retrieveCtrtClnt.set("bizDivBulkYn", scwin.hid_bizDivBulkYn);

                    $c.sbm.execute(sbm_retrieveCtrtClnt);
                }

                hid_ctrtClntNo.setValue(ds_shipmentIndicationOrder.getCellData(s_row, "clntNo")); // 계약거래처번호
                hid_ctrtClntNm.setValue(ds_shipmentIndicationOrder.getCellData(s_row, "clntNm")); // 계약거래처번호

                hid_clntMgntNo.setValue(ds_shipmentIndicationOrder.getCellData(s_row, "mchtOdrNo")); // 거래처관리번호 <- 화주오더번호

                // 회사코드 - 청구거래처 정보 설정
                if (ds_shipmentIndicationOrder.getRowCount() > 0) {
                    if (!$c.gus.cfIsNull(ds_shipmentIndicationOrder.getCellData(s_row, "coBilgClntNo").trim())) {
                        lc_bilgClntNm.setValue(ds_shipmentIndicationOrder.getCellData(s_row, "coBilgClntNo")); // 청구거래처
                    }
                }

                ed_dmndNo.setValue(ds_shipmentIndicationOrder.getCellData(s_row, "dmndNo")); // 고객 -> 수요가
                ed_dmndNo.hidVal = ds_shipmentIndicationOrder.getCellData(s_row, "dmndNo"); // 고객 -> 수요가
                ed_dmndNm.setValue(ds_shipmentIndicationOrder.getCellData(s_row, "dmndNm"));
                ed_dmndNm.hidVal = ds_shipmentIndicationOrder.getCellData(s_row, "dmndNm");
                hid_repClntNo.setValue(ds_shipmentIndicationOrder.getCellData(s_row, "repClntNo")); // 대표거래처번호

                if (!$c.gus.cfIsNull(ds_shipmentIndicationOrder.getCellData(s_row, "selfClsCd")))
                    hid_selfClsCd.setValue(ds_shipmentIndicationOrder.getCellData(s_row, "selfClsCd")); // 자가구분

                tbx_selfClsCd.setValue(hid_selfClsCd.getValue());  // 자가구분 - 표시

                // 정상 오더인경우
                ed_dptWrkPlCd.setValue(ds_shipmentIndicationOrder.getCellData(s_row, "bizWrkPlCd")); // 사업장 - > 출발작업장
                ed_dptWrkPlCd.hidVal = ds_shipmentIndicationOrder.getCellData(s_row, "bizWrkPlCd"); // 사업장 - > 출발작업장
                ed_dptWrkPlNm.setValue(ds_shipmentIndicationOrder.getCellData(s_row, "bizWrkPlNm"));
                ed_dptWrkPlNm.hidVal = ds_shipmentIndicationOrder.getCellData(s_row, "bizWrkPlNm");
                ed_arvWrkPlCd.setValue(ds_shipmentIndicationOrder.getCellData(s_row, "zipWrkPlCd")); // 우편번호 -> 도착작업장
                ed_arvWrkPlCd.hidVal = ds_shipmentIndicationOrder.getCellData(s_row, "zipWrkPlCd"); // 우편번호 -> 도착작업장
                ed_arvWrkPlNm.setValue(ds_shipmentIndicationOrder.getCellData(s_row, "zipWrkPlNm"));
                ed_arvWrkPlNm.hidVal = ds_shipmentIndicationOrder.getCellData(s_row, "zipWrkPlNm");

                ed_arvDtl.setValue(ds_shipmentIndicationOrder.getCellData(s_row, "dtlAddr1"));

                // 출발지(사업장), 도착지(우편번호) 작업장구분과 동일한 작업장 구분인 오더로 설정 - 자가구분설정시 자가구분확인
                for (var i = 0; i < ds_odrKndCd.getRowCount(); i++) {
                    if (ds_shipmentIndicationOrder.getCellData(s_row, "selfClsCd") == "JO" || ds_shipmentIndicationOrder.getCellData(s_row, "selfClsCd") == "JI") {
                        if (ds_odrKndCd.getCellData(i, "dptWrkPlCls") == ds_shipmentIndicationOrder.getCellData(s_row, "bizWrkPlClsCd")
                            && ds_odrKndCd.getCellData(i, "arvWrkPlCls") == ds_shipmentIndicationOrder.getCellData(s_row, "zipWrkPlClsCd")
                            && ds_odrKndCd.getCellData(i, "selfClsCd") == ds_shipmentIndicationOrder.getCellData(s_row, "selfClsCd")) {
                            ds_odrKndCd.setRowPosition(i);
                            break;
                        }
                    } else {
                        if (ds_odrKndCd.getCellData(i, "selfClsCd") !== "JO" && ds_odrKndCd.getCellData(i, "selfClsCd") !== "JI") {
                            if (ds_odrKndCd.getCellData(i, "dptWrkPlCls") == ds_shipmentIndicationOrder.getCellData(s_row, "bizWrkPlClsCd")
                                && ds_odrKndCd.getCellData(i, "arvWrkPlCls") == ds_shipmentIndicationOrder.getCellData(s_row, "zipWrkPlClsCd")) {
                                ds_odrKndCd.setRowPosition(i);
                                break;
                            }
                        }
                    }
                }

                ica_wrkEndDt.setValue(ds_shipmentIndicationOrder.getCellData(s_row, "arvIntendDt"));

                if (scwin.isTime(ds_shipmentIndicationOrder.getCellData(s_row, "arvIntendHh"))) {
                    ed_wrkEndHh.setValue(ds_shipmentIndicationOrder.getCellData(s_row, "arvIntendHh"));
                }

                hid_wrkPatternCd.setValue(ds_shipmentIndicationOrder.getCellData(ds_shipmentIndicationOrder.getRowPosition(), "mchtOdrKndCd"));
                acb_wrkPatternCd.setValue(ds_shipmentIndicationOrder.getCellData(ds_shipmentIndicationOrder.getRowPosition(), "mchtOdrKndCd"));

                ed_offPicNm.setValue(ds_shipmentIndicationOrder.getCellData(s_row, "accp"));
                ed_offPicTelNo.setValue(ds_shipmentIndicationOrder.getCellData(s_row, "tplTelNo")); // 전화번호

                if (scwin.isTime(ds_shipmentIndicationOrder.getCellData(s_row, "arvIntendHh"))) {
                    txt_rmk.setValue(ds_shipmentIndicationOrder.getCellData(s_row, "unqItm")); // 특이사항
                } else {
                    txt_rmk.setValue(ds_shipmentIndicationOrder.getCellData(s_row, "unqItm") + " / 가능한 빨리 처리바람. "); // 특이사항
                }
            }

            if (ds_lobranTrans.getRowCount() > 0) {
                // 매출부서 설정 < -운송부서
                if ($c.gus.cfIsNull(ed_sellLodeptCd.getValue())) {
                    ed_sellLodeptCd.setValue(ds_lobranTrans.getCellData(ds_lobranTrans.getRowPosition(), "lobranCd"));
                    ed_sellLodeptCd.hidVal = ds_lobranTrans.getCellData(ds_lobranTrans.getRowPosition(), "lobranCd");
                }

                if ($c.gus.cfIsNull(ed_sellLodeptNm.getValue())) {
                    ed_sellLodeptNm.setValue(ds_lobranTrans.getCellData(ds_lobranTrans.getRowPosition(), "lobranNm"));
                    ed_sellLodeptNm.hidVal = ds_lobranTrans.getCellData(ds_lobranTrans.getRowPosition(), "lobranNm");
                }
            }

            if (ds_lobranSales.getRowCount() > 0) {
                // 매출부서 설정 < - 영업부서
                if ($c.gus.cfIsNull(ed_bilgLodeptCd.getValue())) {
                    ed_bilgLodeptCd.setValue(ds_lobranSales.getCellData(ds_lobranSales.getRowPosition(), "lobranCd"));
                    ed_bilgLodeptCd.hidVal = ds_lobranSales.getCellData(ds_lobranSales.getRowPosition(), "lobranCd");
                }
                if ($c.gus.cfIsNull(ed_bilgLodeptNm.getValue())) {
                    ed_bilgLodeptNm.setValue(ds_lobranSales.getCellData(ds_lobranSales.getRowPosition(), "lobranNm"));
                    ed_bilgLodeptNm.hidVal = ds_lobranSales.getCellData(ds_lobranSales.getRowPosition(), "lobranNm");
                }
            }

            break;

        case DGauceConstants.TB_JOB_UPDATE: // UPDATE
            // 오더 정보 설정
            if (ds_shipmentIndicationOrder.getRowCount() > 0 && $c.gus.cfIsNull(ds_shipmentIndicationOrder.getCellData(ds_shipmentIndicationOrder.getRowPosition(), "mcomOdrNo"))) {
                var s_row = ds_shipmentIndicationOrder.getRowPosition();

                if (ds_ctrtNo.getRowCount() == 0) { // 계약번호 조회
                    hid_ctrtClntNo.setValue(ds_shipmentIndicationOrder.getCellData(s_row, "clntNo"));

                    dma_retrieveCtrtClnt.set("ctrtClntNo", hid_ctrtClntNo.getValue());
                    dma_retrieveCtrtClnt.set("bizDivCntrYn", scwin.hid_bizDivCntrYn);
                    dma_retrieveCtrtClnt.set("bizDivBulkYn", scwin.hid_bizDivBulkYn);

                    $c.sbm.execute(sbm_retrieveCtrtClnt);
