                hid_ctrtClntNm.setValue(ds_shipmentIndicationOrder.getCellData(s_row, "clntNm")); // 계약거래처번호

                hid_clntMgntNo.setValue(ds_shipmentIndicationOrder.getCellData(s_row, "mchtOdrNo")); // 거래처관리번호 <- 화주오더번호

                // 회사코드 - 청구거래처 정보 설정
                if (ds_shipmentIndicationOrder.getRowCount() > 0) {
                    if (!$c.gus.cfIsNull(ds_shipmentIndicationOrder.getCellData(ds_shipmentIndicationOrder.getRowPosition(), "coBilgClntNo").trim())) {
                        lc_bilgClntNm.setValue(ds_shipmentIndicationOrder.getCellData(ds_shipmentIndicationOrder.getRowPosition(), "coBilgClntNo")); // 청구처
                    }
                }

                ed_dmndNo.setValue(ds_shipmentIndicationOrder.getCellData(s_row, "dmndNo")); // 고객 -> 수요가
                ed_dmndNo.hidVal = ds_shipmentIndicationOrder.getCellData(s_row, "dmndNo"); // 고객 -> 수요가
                ed_dmndNm.setValue(ds_shipmentIndicationOrder.getCellData(s_row, "dmndNm"));
                ed_dmndNm.hidVal = ds_shipmentIndicationOrder.getCellData(s_row, "dmndNm");
                hid_repClntNo.setValue(ds_shipmentIndicationOrder.getCellData(s_row, "repClntNo")); // 대표거래처번호

                if (!$c.gus.cfIsNull(ds_shipmentIndicationOrder.getCellData(s_row, "selfClsCd")))
                    hid_selfClsCd.setValue(ds_shipmentIndicationOrder.getCellData(s_row, "selfClsCd")); // 자가구분

                tbx_selfClsCd.setValue(hid_selfClsCd.getValue());  // 자가구분 - 표시

                if (ds_shipmentIndicationOrder.getCellData(s_row, "mchtOdrKndCd") == "CO"
                    || ds_shipmentIndicationOrder.getCellData(s_row, "mchtOdrKndCd") == "CR"
                    || ds_shipmentIndicationOrder.getCellData(s_row, "mchtOdrKndCd") == "CE"
                    || ds_shipmentIndicationOrder.getCellData(s_row, "mchtOdrKndCd") == "CY"
                    || ds_shipmentIndicationOrder.getCellData(s_row, "mchtOdrKndCd") == "CI"
                    || ds_shipmentIndicationOrder.getCellData(s_row, "mchtOdrKndCd") == "OW") {
                    // 반품 오더인경우
                    ed_dptWrkPlCd.setValue(ds_shipmentIndicationOrder.getCellData(s_row, "zipWrkPlCd")); // 우편번호 -> 출발작업장
                    ed_dptWrkPlCd.hidVal = ds_shipmentIndicationOrder.getCellData(s_row, "zipWrkPlCd"); // 우편번호 -> 출발작업장
                    ed_dptWrkPlNm.setValue(ds_shipmentIndicationOrder.getCellData(s_row, "zipWrkPlNm"));
                    ed_dptWrkPlNm.hidVal = ds_shipmentIndicationOrder.getCellData(s_row, "zipWrkPlNm");
                    ed_arvWrkPlCd.setValue(ds_shipmentIndicationOrder.getCellData(s_row, "bizWrkPlCd")); // 사업장 -> 도착작업장
                    ed_arvWrkPlCd.hidVal = ds_shipmentIndicationOrder.getCellData(s_row, "bizWrkPlCd"); // 사업장 -> 도착작업장
                    ed_arvWrkPlNm.setValue(ds_shipmentIndicationOrder.getCellData(s_row, "bizWrkPlNm"));
                    ed_arvWrkPlNm.hidVal = ds_shipmentIndicationOrder.getCellData(s_row, "bizWrkPlNm");

                    ed_dptDtl.setValue(ds_shipmentIndicationOrder.getCellData(s_row, "dtlAddr1"));

                    // 출발지(우편번호), 도착지(사업장) 작업장구분과 동일한 작업장 구분인 오더로 설정 - 자가구분설정시 자가구분확인
                    for (var i = 0; i < ds_odrKndCd.getRowCount(); i++) {
                        if (ds_shipmentIndicationOrder.getCellData(s_row, "selfClsCd") == "JO" || ds_shipmentIndicationOrder.getCellData(s_row, "selfClsCd") == "JI") {
                            if (ds_odrKndCd.getCellData(i, "dptWrkPlCls") == ds_shipmentIndicationOrder.getCellData(s_row, "zipWrkPlClsCd")
                                && ds_odrKndCd.getCellData(i, "arvWrkPlCls") == ds_shipmentIndicationOrder.getCellData(s_row, "bizWrkPlClsCd")
                                && ds_odrKndCd.getCellData(i, "selfClsCd") == ds_shipmentIndicationOrder.getCellData(s_row, "selfClsCd")) {
                                ds_odrKndCd.setRowPosition(i);
                                break;
                            }
                        } else {
                            if (ds_odrKndCd.getCellData(i, "dptWrkPlCls") == ds_shipmentIndicationOrder.getCellData(s_row, "zipWrkPlClsCd")
                                && ds_odrKndCd.getCellData(i, "arvWrkPlCls") == ds_shipmentIndicationOrder.getCellData(s_row, "bizWrkPlClsCd")) {
                                ds_odrKndCd.setRowPosition(i);
                                break;
                            }
                        }
                    }

                } else if (ds_shipmentIndicationOrder.getCellData(s_row, "mchtOdrKndCd") == "OT"
                    || ds_shipmentIndicationOrder.getCellData(s_row, "mchtOdrKndCd") == "OK"
                    || ds_shipmentIndicationOrder.getCellData(s_row, "mchtOdrKndCd") == "O5") {
                    // 이송오더인 경우

                    // 출발작업장(수요가), 도착작업장(사업장 )
                    ed_dptWrkPlCd.setValue(ds_shipmentIndicationOrder.getCellData(s_row, "dmndWrkPlCd")); // 수요가 -> 출발작업장
                    ed_dptWrkPlCd.hidVal = ds_shipmentIndicationOrder.getCellData(s_row, "dmndWrkPlCd"); // 수요가 -> 출발작업장
