                    ed_dptWrkPlNm.hidVal = ds_shipmentIndicationOrder.getCellData(s_row, "dmndWrkPlNm");
                    ed_arvWrkPlCd.setValue(ds_shipmentIndicationOrder.getCellData(s_row, "bizWrkPlCd")); // 사업장 -> 도착작업장
                    ed_arvWrkPlCd.hidVal = ds_shipmentIndicationOrder.getCellData(s_row, "bizWrkPlCd"); // 사업장 -> 도착작업장
                    ed_arvWrkPlNm.setValue(ds_shipmentIndicationOrder.getCellData(s_row, "bizWrkPlNm"));
                    ed_arvWrkPlNm.hidVal = ds_shipmentIndicationOrder.getCellData(s_row, "bizWrkPlNm");

                    ed_dptDtl.setValue(ds_shipmentIndicationOrder.getCellData(s_row, "dtlAddr1"));

                    // 출발지(사업장), 도착지(우편번호) 작업장구분과 동일한 작업장 구분인 오더로 설정 - 자가구분설정시 자가구분확인                   
                    for (var i = 0; i < ds_odrKndCd.getRowCount(); i++) {
                        if (ds_shipmentIndicationOrder.getCellData(s_row, "selfClsCd") == "JO" || ds_shipmentIndicationOrder.getCellData(s_row, "selfClsCd") == "JI") {
                            if (ds_odrKndCd.getCellData(i, "dptWrkPlCls") == ds_shipmentIndicationOrder.getCellData(s_row, "dmndWrkPlClsCd")
                                && ds_odrKndCd.getCellData(i, "arvWrkPlCls") == ds_shipmentIndicationOrder.getCellData(s_row, "bizWrkPlClsCd")
                                && ds_odrKndCd.getCellData(i, "selfClsCd") == ds_shipmentIndicationOrder.getCellData(s_row, "selfClsCd")) {
                                ds_odrKndCd.setRowPosition(i);
                                break;
                            }
                        } else {
                            if (ds_odrKndCd.getCellData(i, "dptWrkPlCls") == ds_shipmentIndicationOrder.getCellData(s_row, "dmndWrkPlClsCd")
                                && ds_odrKndCd.getCellData(i, "arvWrkPlCls") == ds_shipmentIndicationOrder.getCellData(s_row, "bizWrkPlClsCd")) {
                                ds_odrKndCd.setRowPosition(i);
                                break;
                            }
                        }
                    }
                } else if (ds_shipmentIndicationOrder.getCellData(s_row, "mchtOdrKndCd") == "ST"
                    || ds_shipmentIndicationOrder.getCellData(s_row, "mchtOdrKndCd") == "S5") {

                    // 이동판매 오더인 경우

                    // 출발작업장(사업장), 도착작업장(수요가)
                    ed_dptWrkPlCd.setValue(ds_shipmentIndicationOrder.getCellData(s_row, "bizWrkPlCd")); // 사업장 -> 출발작업장
                    ed_dptWrkPlCd.hidVal = ds_shipmentIndicationOrder.getCellData(s_row, "bizWrkPlCd"); // 사업장 -> 출발작업장
                    ed_dptWrkPlNm.setValue(ds_shipmentIndicationOrder.getCellData(s_row, "bizWrkPlNm"));
                    ed_dptWrkPlNm.hidVal = ds_shipmentIndicationOrder.getCellData(s_row, "bizWrkPlNm");
                    ed_arvWrkPlCd.setValue(ds_shipmentIndicationOrder.getCellData(s_row, "dmndWrkPlCd")); // 수요가 -> 도착작업장
                    ed_arvWrkPlCd.hidVal = ds_shipmentIndicationOrder.getCellData(s_row, "dmndWrkPlCd"); // 수요가 -> 도착작업장
                    ed_arvWrkPlNm.setValue(ds_shipmentIndicationOrder.getCellData(s_row, "dmndWrkPlNm"));
                    ed_arvWrkPlNm.hidVal = ds_shipmentIndicationOrder.getCellData(s_row, "dmndWrkPlNm");

                    ed_arvDtl.setValue(ds_shipmentIndicationOrder.getCellData(s_row, "dtlAddr1"));

                    // 출발지(사업장), 도착지(우편번호) 작업장구분과 동일한 작업장 구분인 오더로 설정 - 자가구분설정시 자가구분확인                    
                    for (var i = 0; i < ds_odrKndCd.getRowCount(); i++) {
                        if (ds_shipmentIndicationOrder.getCellData(s_row, "selfClsCd") == "JO" || ds_shipmentIndicationOrder.getCellData(s_row, "selfClsCd") == "JI") {
                            if (ds_odrKndCd.getCellData(i, "dptWrkPlCls") == ds_shipmentIndicationOrder.getCellData(s_row, "bizWrkPlClsCd")
                                && ds_odrKndCd.getCellData(i, "arvWrkPlCls") == ds_shipmentIndicationOrder.getCellData(s_row, "dmndWrkPlClsCd")
                                && ds_odrKndCd.getCellData(i, "selfClsCd") == ds_shipmentIndicationOrder.getCellData(s_row, "selfClsCd")) {
                                ds_odrKndCd.setRowPosition(i);
                                break;
                            }
                        } else {
                            if (ds_odrKndCd.getCellData(i, "dptWrkPlCls") == ds_shipmentIndicationOrder.getCellData(s_row, "bizWrkPlClsCd")
                                && ds_odrKndCd.getCellData(i, "arvWrkPlCls") == ds_shipmentIndicationOrder.getCellData(s_row, "dmndWrkPlClsCd")) {
                                ds_odrKndCd.setRowPosition(i);
                                break;
                            }
                        }
                    }

                } else {
                    // 정상 오더인경우
                    ed_dptWrkPlCd.setValue(ds_shipmentIndicationOrder.getCellData(s_row, "bizWrkPlCd")); // 사업장 - > 출발작업장
                    ed_dptWrkPlCd.hidVal = ds_shipmentIndicationOrder.getCellData(s_row, "bizWrkPlCd"); // 사업장 - > 출발작업장
                    ed_dptWrkPlNm.setValue(ds_shipmentIndicationOrder.getCellData(s_row, "bizWrkPlNm"));
                    ed_dptWrkPlNm.hidVal = ds_shipmentIndicationOrder.getCellData(s_row, "bizWrkPlNm");
                    ed_arvWrkPlCd.setValue(ds_shipmentIndicationOrder.getCellData(s_row, "zipWrkPlCd")); // 우편번호 -> 도착작업장
                    ed_arvWrkPlCd.hidVal = ds_shipmentIndicationOrder.getCellData(s_row, "zipWrkPlCd"); // 우편번호 -> 도착작업장
                    ed_arvWrkPlNm.setValue(ds_shipmentIndicationOrder.getCellData(s_row, "zipWrkPlNm"));
                    ed_arvWrkPlNm.hidVal = ds_shipmentIndicationOrder.getCellData(s_row, "zipWrkPlNm");

                    ed_arvDtl.setValue(ds_shipmentIndicationOrder.getCellData(s_row, "dtlAddr1"));

                    // 출발지(사업장), 도착지(우편번호) 작업장구분과 동일한 작업장 구분인 오더로 설정 - 자가구분설정시 자가구분확인                    
                    for (var i = 0; i < ds_odrKndCd.getRowCount(); i++) {
                        if (ds_shipmentIndicationOrder.getCellData(s_row, "selfClsCd") == "JO" || ds_shipmentIndicationOrder.getCellData(s_row, "selfClsCd") == "JI") {
                            if (ds_odrKndCd.getCellData(i, "dptWrkPlCls") == ds_shipmentIndicationOrder.getCellData(s_row, "bizWrkPlClsCd")
                                && ds_odrKndCd.getCellData(i, "arvWrkPlCls") == ds_shipmentIndicationOrder.getCellData(s_row, "zipWrkPlClsCd")
                                && ds_odrKndCd.getCellData(i, "selfClsCd") == ds_shipmentIndicationOrder.getCellData(s_row, "selfClsCd")) {
                                ds_odrKndCd.setRowPosition(i);
                                break;
                            }
                        } else {
                            if (ds_odrKndCd.getCellData(i, "dptWrkPlCls") == ds_shipmentIndicationOrder.getCellData(s_row, "bizWrkPlClsCd")
                                && ds_odrKndCd.getCellData(i, "arvWrkPlCls") == ds_shipmentIndicationOrder.getCellData(s_row, "zipWrkPlClsCd")) {
                                ds_odrKndCd.setRowPosition(i);
                                break;
                            }
                        }
                    }
                }

                hid_wrkPatternCd.setValue(ds_shipmentIndicationOrder.getCellData(ds_shipmentIndicationOrder.getRowPosition(), "mchtOdrKndCd"));
                acb_wrkPatternCd.setValue(ds_shipmentIndicationOrder.getCellData(ds_shipmentIndicationOrder.getRowPosition(), "mchtOdrKndCd"));

                ed_offPicNm.setValue(ds_shipmentIndicationOrder.getCellData(s_row, "accp"));
                ed_offPicTelNo.setValue(ds_shipmentIndicationOrder.getCellData(s_row, "tplTelNo")); // 전화번호

                if (scwin.isTime(ds_shipmentIndicationOrder.getCellData(s_row, "arvIntendHh"))) {
                    txt_rmk.setValue(ds_shipmentIndicationOrder.getCellData(s_row, "unqItm")); // 특이사항
                } else {
                    txt_rmk.setValue(ds_shipmentIndicationOrder.getCellData(s_row, "unqItm") + " / 가능한 빨리 처리바람. "); // 특이사항
                }

            }
            break;

        case DGauceConstants.TB_JOB_DELETE: // DELETE

            break;

        default:

            break;
    }
};

//-------------------------------------------------------------------------
// 시간(HHmm) 형식의 값인지 확인
//-------------------------------------------------------------------------
scwin.isTime = function (sTime) {
    let flag = true;
    try {
        if (sTime.length != 4) {
            return false;
        }
        const h1 = parseInt(sTime.substring(0, 2), 10);
        const t1 = parseInt(sTime.substring(2, 4), 10);

        if (isNaN(h1) || isNaN(t1))
            flag = false;

        if (h1 + t1 != "") {
            if (h1 < 0 || h1 > 24) {
                flag = false;
            } else if (h1 == 24) {
                if (typeof timeChk == "boolean" && !timeChk)
                    flag = false;
                if (t1 > 0)
                    flag = false;
            }
            if (t1 < 0 || t1 > 59)
                flag = false;
        }
    } catch (ex) {
        console.error(ex);
        flag = false;
    }
    return flag;
};

//-------------------------------------------------------------------------
// 오더요청 품명 정보를 오더 품명 정보에 설정
//-------------------------------------------------------------------------
scwin.f_setOrderCommodityInformation = function (jobType) {

    switch (jobType) {
        case DGauceConstants.TB_JOB_INSERT: // INSERT           
            // 오더 품명 정보 설정
            if (ds_shipmentIndicationCommodity.getRowCount() > 0 && ds_orderCommodity.getRowCount() == 0) {
                for (var i = 0; i < ds_shipmentIndicationCommodity.getRowCount(); i++) {
                    var oc_row = ds_orderCommodity.insertRow();
                    ds_orderCommodity.setRowPosition(oc_row);

                    ds_orderCommodity.setCellData(oc_row, "odrNo", ds_order.getCellData(ds_order.getRowPosition(), "odrNo")); // 오더번호
                    ds_orderCommodity.setCellData(oc_row, "commSeq", i + 1); // 품명순번
                    ds_orderCommodity.setCellData(oc_row, "commCd", ds_shipmentIndicationCommodity.getCellData(i, "commCd")); // 품명코드
                    ds_orderCommodity.setCellData(oc_row, "commNm", ds_shipmentIndicationCommodity.getCellData(i, "commNm")); // 품명
                    ds_orderCommodity.setCellData(oc_row, "qtyUnitCd", ds_shipmentIndicationCommodity.getCellData(i, "internalQtyUnit")); // 단위코드 <- 내부 수량 단위
                    ds_orderCommodity.setCellData(oc_row, "unitCd", ds_shipmentIndicationCommodity.getCellData(i, "internalWtUnit")); // 단위코드 <- 내부 중량 단위
                    ds_orderCommodity.setCellData(oc_row, "qty", ds_shipmentIndicationCommodity.getCellData(i, "qty")); // 수량
                    ds_orderCommodity.setCellData(oc_row, "grossWt", ds_shipmentIndicationCommodity.getCellData(i, "wt")); // 중량
                    ds_orderCommodity.setCellData(oc_row, "cstmrMgntNo", ds_shipmentIndicationCommodity.getCellData(i, "tplMgntNo")); // 고객관리번호 <- 관리번호
                    ds_orderCommodity.setCellData(oc_row, "mgntSeq", ds_shipmentIndicationCommodity.getCellData(i, "mgntSeq")); // 관리순번
                    ds_orderCommodity.setCellData(oc_row, "coCd", ds_shipmentIndicationCommodity.getCellData(i, "coCd")); // 회사코드
                    ds_orderCommodity.setCellData(oc_row, "bizLongCd", ds_shipmentIndicationCommodity.getCellData(i, "bizLongCd")); // 사업장코드
                    ds_orderCommodity.setCellData(oc_row, "tplArvNmCmpy", ds_shipmentIndicationCommodity.getCellData(i, "shipTo")); //

                    ds_orderCommodity.setCellData(oc_row, "wrkStDt", ica_wrkStDt.getValue()); // 작업시작일자
                    ds_orderCommodity.setCellData(oc_row, "wrkStHh", ed_wrkStHh.getValue()); // 작업시작시간
                    ds_orderCommodity.setCellData(oc_row, "wrkEndDt", ica_wrkEndDt.getValue()); // 작업종료일자
                    ds_orderCommodity.setCellData(oc_row, "wrkEndHh", ed_wrkEndHh.getValue()); // 작업종료시간

                    // 출발작업장코드, 도착작업장코드 자동 설정
                    ds_orderCommodity.setCellData(oc_row, "dptWrkPlCd", ed_dptWrkPlCd.getValue().trim());
                    ds_orderCommodity.setCellData(oc_row, "arvWrkPlCd", ed_arvWrkPlCd.getValue().trim());

                    // 영업담당자 정보 설정
                    if (i == 0) {
                        hid_salesPicNm.setValue(ds_shipmentIndicationCommodity.getCellData(i, "salesPicNm")); // 영업담당자명
                        hid_salesPicTelNo.setValue(ds_shipmentIndicationCommodity.getCellData(i, "salesPicTelNo")); // 영업담당자 전화번호
                        hid_tplPgmId.setValue(ds_shipmentIndicationCommodity.getCellData(i, "tplPgmId")); // 영업담당자 전화번호
                    }

                    ds_orderCommodity.setCellData(i, "cnclYn", DsConstants.YN_NO);
                }
            }

            break;
        case DGauceConstants.TB_JOB_UPDATE: // UPDATE

            // 오더 품명 정보 설정
            if (ds_shipmentIndicationCommodity.getRowCount() > 0 && $c.gus.cfIsNull(ds_shipmentIndicationOrder.getCellData(ds_shipmentIndicationOrder.getRowPosition(), "mcomOdrNo"))) {
                for (var i = 0; i < ds_shipmentIndicationCommodity.getRowCount(); i++) {
                    if (ds_shipmentIndicationCommodity.getCellData(i, "stsClsCd") == "I") {
                        // 품명 추가
                        var oc_row = ds_orderCommodity.insertRow();
                        ds_orderCommodity.setRowPosition(oc_row);

                        ds_orderCommodity.setCellData(oc_row, "odrNo", ds_order.getCellData(ds_order.getRowPosition(), "odrNo")); // 오더번호
                        ds_orderCommodity.setCellData(oc_row, "commSeq", i + 1); // 품명순번
                        ds_orderCommodity.setCellData(oc_row, "commCd", ds_shipmentIndicationCommodity.getCellData(i, "commCd")); // 품명코드
                        ds_orderCommodity.setCellData(oc_row, "commNm", ds_shipmentIndicationCommodity.getCellData(i, "commNm")); // 품명
                        ds_orderCommodity.setCellData(oc_row, "qtyUnitCd", ds_shipmentIndicationCommodity.getCellData(i, "internalQtyUnit")); // 단위코드 <- 내부 수량 단위
                        ds_orderCommodity.setCellData(oc_row, "unitCd", ds_shipmentIndicationCommodity.getCellData(i, "internalWtUnit")); // 단위코드 <- 내부 중량 단위
                        ds_orderCommodity.setCellData(oc_row, "qty", ds_shipmentIndicationCommodity.getCellData(i, "qty")); // 수량
                        ds_orderCommodity.setCellData(oc_row, "grossWt", ds_shipmentIndicationCommodity.getCellData(i, "wt")); // 중량
                        ds_orderCommodity.setCellData(oc_row, "cstmrMgntNo", ds_shipmentIndicationCommodity.getCellData(i, "tplMgntNo")); // 고객관리번호 <- 관리번호
                        ds_orderCommodity.setCellData(oc_row, "mgntSeq", ds_shipmentIndicationCommodity.getCellData(i, "mgntSeq")); // 관리순번
                        ds_orderCommodity.setCellData(oc_row, "coCd", ds_shipmentIndicationCommodity.getCellData(i, "coCd")); // 회사코드
                        ds_orderCommodity.setCellData(oc_row, "bizLongCd", ds_shipmentIndicationCommodity.getCellData(i, "bizLongCd")); // 사업장코드
                        ds_orderCommodity.setCellData(oc_row, "tplArvNmCmpy", ds_shipmentIndicationCommodity.getCellData(i, "shipTo")); //

                        ds_orderCommodity.setCellData(oc_row, "wrkStDt", ica_wrkStDt.getValue()); // 작업시작일자
                        ds_orderCommodity.setCellData(oc_row, "wrkStHh", ed_wrkStHh.getValue()); // 작업시작시간
                        ds_orderCommodity.setCellData(oc_row, "wrkEndDt", ica_wrkEndDt.getValue()); // 작업종료일자
                        ds_orderCommodity.setCellData(oc_row, "wrkEndHh", ed_wrkEndHh.getValue()); // 작업종료시간

                        // 출발작업장코드, 도착작업장코드 자동 설정
                        ds_orderCommodity.setCellData(oc_row, "dptWrkPlCd", ed_dptWrkPlCd.getValue().trim());
                        ds_orderCommodity.setCellData(oc_row, "arvWrkPlCd", ed_arvWrkPlCd.getValue().trim());

                        ds_orderCommodity.setCellData(oc_row, "cnclYn", scwin.DsConstants.YN_NO);

                        // 영업담당자 정보 설정
                        if (i == 0) {
                            hid_salesPicNm.setValue(ds_shipmentIndicationCommodity.getCellData(i, "salesPicNm")); // 영업담당자명
                            hid_salesPicTelNo.setValue(ds_shipmentIndicationCommodity.getCellData(i, "salesPicTelNo")); // 영업담당자 전화번호
                            hid_tplPgmId.setValue(ds_shipmentIndicationCommodity.getCellData(i, "tplPgmId")); // 영업담당자 전화번호
                        }

                    } else if (ds_shipmentIndicationCommodity.getCellData(i, "stsClsCd") == "U") {

                        // 품명 데이터 셋에서 해당 품명을 찾아 정보를 변경
                        for (j = 0; j < ds_orderCommodity.getRowCount(); j++) {

                            if (ds_orderCommodity.getCellData(j, "commCd") == ds_shipmentIndicationCommodity.getCellData(i, "commCd")) { // 품명코드

                                ds_orderCommodity.setCellData(j, "qtyUnitCd", ds_shipmentIndicationCommodity.getCellData(i, "internalQtyUnit")); // 단위코드 <- 내부 수량 단위
                                ds_orderCommodity.setCellData(j, "unitCd", ds_shipmentIndicationCommodity.getCellData(i, "internalWtUnit")); // 단위코드 <- 내부 중량 단위
                                ds_orderCommodity.setCellData(j, "qty", ds_shipmentIndicationCommodity.getCellData(i, "qty")); // 수량
                                ds_orderCommodity.setCellData(j, "grossWt", ds_shipmentIndicationCommodity.getCellData(i, "wt")); // 중량
                                ds_orderCommodity.setCellData(j, "cstmrMgntNo", ds_shipmentIndicationCommodity.getCellData(i, "tplMgntNo")); // 고객관리번호 <- 관리번호
                                ds_orderCommodity.setCellData(j, "mgntSeq", ds_shipmentIndicationCommodity.getCellData(i, "mgntSeq")); // 관리순번
                                ds_orderCommodity.setCellData(j, "coCd", ds_shipmentIndicationCommodity.getCellData(i, "coCd")); // 회사코드
                                ds_orderCommodity.setCellData(j, "bizLongCd", ds_shipmentIndicationCommodity.getCellData(i, "bizLongCd")); // 사업장코드
                                ds_orderCommodity.setCellData(j, "tplArvNmCmpy", ds_shipmentIndicationCommodity.getCellData(i, "shipTo")); //

                                ds_orderCommodity.setCellData(j, "wrkStDt", ica_wrkStDt.getValue()); // 작업시작일자
                                ds_orderCommodity.setCellData(j, "wrkStHh", ed_wrkStHh.getValue()); // 작업시작시간
                                ds_orderCommodity.setCellData(j, "wrkEndDt", ica_wrkEndDt.getValue()); // 작업종료일자
                                ds_orderCommodity.setCellData(j, "wrkEndHh", ed_wrkEndHh.getValue()); // 작업종료시간

                                // 출발작업장코드, 도착작업장코드 자동 설정
                                ds_orderCommodity.setCellData(j, "dptWrkPlCd", ed_dptWrkPlCd.getValue().trim());
