//-------------------------------------------------------------------------
// 출발일자를 도착일자 -1 일로 세팅한다.
//-------------------------------------------------------------------------
scwin.f_DptDtSet1 = async function () {
    ds_holiday.setCellData(0, "mchtOdrFromDt", "20050101");

    const sDate = ica_wrkEndDt.getValue().trim(); 
    const yyyy = sDate.substring(0, 4);
    const MM   = sDate.substring(4, 6);
    const dd   = sDate.substring(6, 8);

    let date = new Date(Number(yyyy), Number(MM) - 1, Number(dd));

    date.setDate(date.getDate() - 1);

    const resYear = date.getFullYear();
    const resMonth = ("0" + (date.getMonth() + 1)).slice(-2);
    const resDay = ("0" + date.getDate()).slice(-2);

    const prevday = `${resYear}${resMonth}${resDay}`;

    // dma_condHoliday.set("prevday" + prevday);
    // ds_holiday.setCellData(0, "mchtOdrFromDt");
    $c.sbm.setAction(sbm_reterieveHoliday, "/ncall.ds.sd.odrmgnt.odrreg.RetrieveBeforeBusinessDayCMD.do?prevday=" + prevday);
    await $c.sbm.execute(sbm_reterieveHoliday);

};

