//-------------------------------------------------------------------------
// 오더요청등록 조회 submitdone
//-------------------------------------------------------------------------
scwin.sbm_reterieve_submitdone = function (e) {

    // exception 넘어온 경우 다른 로직 타지 않도록 처리
    if (e.responseJSON.resultDataSet[0].Code < 0) return;

    ds_shipmentIndicationCommodityTemp.setJSON(e.responseJSON["OUT_DS2"]);

    // TOBE : 오더요청 품명목록 그리드 - 계약작업경로순번 컬럼값이 콤보박스에 없는 경우 표시가 안되어 데이터리스트에 추가
    for (var i = 0; i < ds_shipmentIndicationCommodityTemp.getRowCount(); i++) {
        var ctrtWrkPathSeq = ds_shipmentIndicationCommodityTemp.getCellData(i, "ctrtWrkPathSeq");
        var rows = ds_ctrtWrkPath.getMatchedIndex("ctrtWrkPathSeq", ctrtWrkPathSeq);

        if (rows.length == 0) {
            var newRow = ds_ctrtWrkPath.insertRow();
            ds_ctrtWrkPath.setCellData(newRow, "ctrtWrkPathSeq", ctrtWrkPathSeq);
            ds_ctrtWrkPath.setCellData(newRow, "ctrtWrkPathNm", ctrtWrkPathSeq);
        }
    }

    // 콤보박스 데이터리스트 추가 후 다시 SET
    ds_shipmentIndicationCommodity.setJSON(ds_shipmentIndicationCommodityTemp.getAllJSON());

    scwin.ds_shipmentIndicationOrder_OnLoadCompleted();
    scwin.ds_shipmentIndicationCommodity_OnLoadCompleted();

    // 여기서 실행하면 데이터 세팅 안됨 scwin.ds_order_OnLoadCompleted();
    scwin.ds_order_OnLoadCompleted();
    //scwin.ds_ctrtNo_OnLoadCompleted();
    scwin.ds_reqClntNo_OnLoadCompleted();
    scwin.ds_bilgClntNo_OnLoadCompleted();
    scwin.ds_wrkPatternCd_OnLoadCompleted();

    if (ds_order.getRowCount() > 0) {
        ed_clntNo.setValue(ds_order.getCellData(ds_order.getRowPosition(), "ctrtClntNo"));
        ed_clntNo.hidVal = ds_order.getCellData(ds_order.getRowPosition(), "ctrtClntNo");
        ed_clntNm.setValue(ds_order.getCellData(ds_order.getRowPosition(), "ctrtClntNm"));
        ed_clntNm.hidVal = ds_order.getCellData(ds_order.getRowPosition(), "ctrtClntNm");

        var v_wrkPatternCd = ds_order.getCellData(ds_order.getRowPosition(), "wrkPatternCd");
        acb_wrkPatternCd.setValue(v_wrkPatternCd);
        if (acb_mchtOdrKndCd.getSelectedIndex() == 0) {
            acb_mchtOdrKndCd.setValue(v_wrkPatternCd);
        }

        ed_mchtOdrNo.setValue(ds_order.getCellData(ds_order.getRowPosition(), "clntMgntNo"));
        ed_mcomOdrNo.setValue(ds_order.getCellData(ds_order.getRowPosition(), "odrNo"));

        if (ds_lobranTrans.getRowCount() > 0) {
            // 매출부서 설정 < -운송부서
            if ($c.gus.cfIsNull(ed_sellLodeptCd.getValue())) {
                ed_sellLodeptCd.setValue(ds_lobranTrans.getCellData(ds_lobranTrans.getRowPosition(), "lobranCd"));
                ed_sellLodeptCd.hidVal = ds_lobranTrans.getCellData(ds_lobranTrans.getRowPosition(), "lobranCd");
            }

            if ($c.gus.cfIsNull(ed_sellLodeptNm.getValue())) {
                ed_sellLodeptNm.setValue(ds_lobranTrans.getCellData(ds_lobranTrans.getRowPosition(), "lobranNm"));
                ed_sellLodeptNm.hidVal = ds_lobranTrans.getCellData(ds_lobranTrans.getRowPosition(), "lobranNm");
            }

        }

        if (ds_lobranSales.getRowCount() > 0) {
            // 매출부서 설정 < - 영업부서
            if ($c.gus.cfIsNull(ed_bilgLodeptCd.getValue())) {
                ed_bilgLodeptCd.setValue(ds_lobranSales.getCellData(ds_lobranSales.getRowPosition(), "lobranCd"));
                ed_bilgLodeptCd.hidVal = ds_lobranSales.getCellData(ds_lobranSales.getRowPosition(), "lobranCd");
            }
            if ($c.gus.cfIsNull(ed_bilgLodeptNm.getValue())) {
                ed_bilgLodeptNm.setValue(ds_lobranSales.getCellData(ds_lobranSales.getRowPosition(), "lobranNm"));
                ed_bilgLodeptNm.hidVal = ds_lobranSales.getCellData(ds_lobranSales.getRowPosition(), "lobranNm");
            }
        }

        //자가구분 표시
        tbx_selfClsCd.setValue(ds_order.getCellData(ds_order.getRowPosition(), "selfClsCd"));

        //합적여부 표시
        if (ds_order.getCellData(ds_order.getRowPosition(), "selfClsCd") == 'JO' && ds_shipmentIndicationCommodity.getRowCount() > 1) {
            rd_coshippingYn.setValue("1");
        }

        // 확정 여부 표시
        if (ds_order.getCellData(ds_order.getRowPosition(), "odrDcsnYn") != DsConstants.YN_YES)
            tbx_odrDcsnYn.setValue("미확정");
        else
            tbx_odrDcsnYn.setValue("확정");

        // 출발일자, 도착일자 초기값 설정
        if ($c.gus.cfIsNull(ica_wrkEndDt.getValue()))
            ica_wrkEndDt.setValue(scwin.strCurDate);

        // 오더 담당 정보 설정
        if ($c.gus.cfIsNull(ed_odrPicNm.getValue())) ed_odrPicNm.setValue(scwin.userNm);
        if ($c.gus.cfIsNull(ed_odrPicTelNo.getValue())) ed_odrPicTelNo.setValue(scwin.userMpNo);

        if (ds_shipmentIndicationOrder.getRowCount() > 0) {
            if ($c.gus.cfIsNull(ds_shipmentIndicationOrder.getCellData(ds_shipmentIndicationOrder.getRowPosition(), "mcomOdrNo").trim())) {
                $c.gus.cfEnableObjects(tbl_order);
                $c.gus.cfDisableBtnOnly([btn_update]);
                $c.gus.cfEnableBtnOnly([btn_save]);
                gr_shipmentIndicationCommodityList.setReadOnly("grid", false);
            } else {
                $c.gus.cfDisableObjects(tbl_order);

                if (ds_order.getCellData(ds_order.getRowPosition(), "odrDelYn") != DsConstants.YN_YES) {
                    $c.gus.cfEnableBtnOnly([btn_update]);
                } else {
                    $c.gus.cfDisableBtnOnly([btn_update]);
                }

                $c.gus.cfDisableObjects([btn_save]);
                gr_shipmentIndicationCommodityList.setReadOnly("grid", true);

            }
        }

        if (ds_ctrtNo.getRowCount() == 0 && ds_shipmentIndicationOrder.getRowCount() > 0) {

            //$c.gus.cfAlertMsg("거래처 %의 " + MSG_CM_ERR_049, new Array(ed_clntNm.getValue(), "계약번호"));
            $c.gus.cfAlertMsg($p, MSG_CM_ERR_049, new Array("거래처 " + ed_clntNm.getValue() + "의 계약번호"))
        }

        if (hid_odrWrkPathCnt.getValue() > 0 && hid_odrWrkPathCnt.getValue() == ds_orderCommodity.getRowCount()) {
            // 작업경로가 지정된 경우
            if (hid_odrDcsnYn.getValue() != DsConstants.YN_YES) {
                // 오더가 확정 되지 않은 경우
                $c.gus.cfEnableBtnOnly([btn_update]);
            } else {
                // 오더가 확정된 경우     
                $c.gus.cfEnableBtnOnly([btn_update]);

                if (hid_odrCompleteYn.getValue() != DsConstants.YN_YES) {
                    // 오더가 완료 되지 않은 경우
                } else {
                    // 오더가 완료된 경우
                    $c.gus.cfDisableBtnOnly([btn_update]);
                }
            }
        }

        // 오더 Sheet 발행 버튼 활성화 - 당사 오더가 생성된 경우 발행 가능
        if (!$c.gus.cfIsNull(ds_order.getCellData(ds_order.getRowPosition(), "odrNo").trim()))
            $c.gus.cfEnableObjects([btn_orderSheetPrint]);
        else
            $c.gus.cfDisableObjects([btn_orderSheetPrint]);

        hid_odrKndCd.setValue(ds_order.getCellData(ds_order.getRowPosition(), "odrKndCd")); // 오더 종류 설정
        acb_odrKndCd.setValue(ds_order.getCellData(ds_order.getRowPosition(), "odrKndCd"));
    }

    if (ed_mcomOdrNo.getValue() != "") {
        $c.gus.cfDisableObjects([btn_commsave]);
    } else {
        $c.gus.cfEnableObjects([btn_commsave]);
    }

    ds_order.reform(); // ASIS 로컬과 개발서버의 환경이 다른지 조회후 저장버튼을 누르면 변경사항이 없다는 문구가 떠서 해당 로직 추가

    scwin.params = $c.data.getParameter();

    const val = scwin.params.clntNo;
    lc_ctrtNo.setValue(val);
    scwin.lc_ctrtNo_onchange({
    // scwin.lc_ctrtNo_onviewchange({
        newValue: val,
        oldValue: ""
    });

};

