// ASIS : ds_mchtOdrKndCd event=OnLoadCompleted(rowCnt)
//-------------------------------------------------------------------------
scwin.ds_mchtOdrKndCd_ondataload = function () {
    if (ds_mchtOdrKndCd.getRowCount() == 0) {
        $c.gus.cfAlertMsg("화주오더종류의 " + MSG_CM_ERR_003, new Array("화주오더종류"));
        //$c.gus.cfAlertMsg($p, MSG_CM_ERR_003, new Array("화주오더종류의 "));
    } else {
        ds_mchtOdrKndCd.insertRow(0);
        //ds_mchtOdrKndCd.setRowPosition(0);
        ds_mchtOdrKndCd.setCellData(0, "osideCd", "");
        ds_mchtOdrKndCd.setCellData(0, "osideCdNm", "선택");
        acb_mchtOdrKndCd.setSelectedIndex(0);
    }
};

//-------------------------------------------------------------------------
// 작업유형 dataList OnLoadCompleted 처리(ondataload 이벤트는 바인드 되기전에 호출되므로 사용하면 안됨)
// ASIS : ds_wrkPatternCd event=OnLoadCompleted(rowCnt)
//-------------------------------------------------------------------------
scwin.ds_wrkPatternCd_OnLoadCompleted = function () {
    if (ds_wrkPatternCd.getRowCount() == 0) {
        //$c.gus.cfAlertMsg("%의 " + MSG_CM_ERR_003, new Array("작업유형"));
        $c.gus.cfAlertMsg($p, MSG_CM_ERR_003, new Array("작업유형의 "));
    } else {
        ds_wrkPatternCd.insertRow(0);
        ds_wrkPatternCd.setRowPosition(0);
        ds_wrkPatternCd.setCellData(0, "osideCd", "");
        ds_wrkPatternCd.setCellData(0, "osideCdNm", "선택");

        if (ds_mchtOdrKndCd.getRowCount() <= 1) {
            $c.gus.cfCopyDataSet(ds_wrkPatternCd, ds_mchtOdrKndCd, "copyHeader=yes");
        }

        acb_mchtOdrKndCd.setValue(scwin.hid_mchtOdrKndCd);
    }

};

//-------------------------------------------------------------------------
// 오더요청 기본정보 dataList OnLoadCompleted 처리(ondataload 이벤트는 바인드 되기전에 호출되므로 사용하면 안됨)
// ASIS : ds_shipmentIndicationOrder event=OnLoadCompleted(rowCnt)
//-------------------------------------------------------------------------
scwin.ds_shipmentIndicationOrder_OnLoadCompleted = function () {
    if (ds_shipmentIndicationOrder.getRowCount() == 0) {
        ds_order.setJSON([])
        ds_order.insertRow(0);
        ds_order.setRowPosition(0);
        //$c.gus.cfAlertMsg("%의 " + MSG_CM_ERR_003, new Array("오더요청"));
        $c.gus.cfAlertMsg($p, MSG_CM_ERR_003, new Array("오더요청의 "));
        return;
    } else {
        ds_shipmentIndicationOrder.setRowPosition(0);
    }
};

//-------------------------------------------------------------------------
// 오더요청 기본정보 dataList ondataload
// ASIS : ds_shipmentIndicationOrder event=OnRowPosChanged(row)
//-------------------------------------------------------------------------
scwin.ds_shipmentIndicationOrder_onrowpositionchange = function (info) {

    if (info.newRowIndex > -1) {
        tbx_ctrtClntNo.setValue(ds_shipmentIndicationOrder.getCellData(info.newRowIndex, "clntNm")); // 계약거래처명
        hid_ctrtClntNo.setValue(ds_shipmentIndicationOrder.getCellData(info.newRowIndex, "clntNo")); // 계약거래처번호
        hid_ctrtClntNm.setValue(ds_shipmentIndicationOrder.getCellData(info.newRowIndex, "clntNm")); // 계약거래처명

        tbx_odrRecptDtm.setValue(ds_shipmentIndicationOrder.getCellData(info.newRowIndex, "tplPgmId")); // 납품처명 ??
        tbx_odrCreatId.setValue(ds_shipmentIndicationOrder.getCellData(info.newRowIndex, "tplErrMsg")); // 발주처명 ??

        tbx_odrCreatDtm.setValue(ds_shipmentIndicationOrder.getCellData(info.newRowIndex, "workstationId")); // 전표번호

        // 상태구분코드 에 따른 오더 작업 일시 라벨 변경
        dscommon.cf_HideObject([tbx_odrCnclItem, acb_odrCnclItemCd]);

        switch (ds_shipmentIndicationOrder.getCellData(info.newRowIndex, "stsClsCd").toUpperCase()) {
            case "I":
                tbx_odrCreatDtmlbl.setValue("전표번호");
                break;
            case "D":
                dscommon.cf_ShowObject([tbx_odrCnclItem, acb_odrCnclItemCd]);
                break;
            default:
                tbx_odrCreatDtmlbl.setValue("전표번호");
                break;
        }


        tbx_mchtOdrKndCdNm.setValue("[" + ds_shipmentIndicationOrder.getCellData(info.newRowIndex, "mchtOdrKndCd") + "]" + ds_shipmentIndicationOrder.getCellData(info.newRowIndex, "mchtOdrKndNm")); // 화주오더종류
        tbx_mchtOdrNo.setValue(ds_shipmentIndicationOrder.getCellData(info.newRowIndex, "mchtOdrNo")); // 화주오더번호

        if (!$c.gus.cfIsNull(ds_shipmentIndicationOrder.getCellData(info.newRowIndex, "odrDt").trim()))
            tbx_odrDt.setValue(ds_shipmentIndicationOrder.getCellData(info.newRowIndex, "odrDt").toDate("YYYYMMDD").format("YYYY/MM/DD")); // 화주오더일자
        else
            tbx_odrDt.setValue("");

        tbx_bizLongCdNm.setValue(ds_shipmentIndicationOrder.getCellData(info.newRowIndex, "bizLongNm")); // 공장구분

        if (scwin.isTime(ds_shipmentIndicationOrder.getCellData(info.newRowIndex, "arvIntendHh"))) {
            tbx_arvIntendDtm.setValue((ds_shipmentIndicationOrder.getCellData(info.newRowIndex, "arvIntendDt") + ds_shipmentIndicationOrder.getCellData(info.newRowIndex, "arvIntendHh")).toDate("YYYYMMDDHHmm").format("YYYY/MM/DD HH:mm:ss"));    // 도착예정일시
        } else {
            tbx_arvIntendDtm.setValue((ds_shipmentIndicationOrder.getCellData(info.newRowIndex, "arvIntendDt")).toDate("YYYYMMDD").format("YYYY/MM/DD") + " " + ds_shipmentIndicationOrder.getCellData(info.newRowIndex, "arvIntendHh"));  // 도착예정일시
        }

        tbx_zip.setValue(ds_shipmentIndicationOrder.getCellData(info.newRowIndex, "zipNm")); // 우편번호
        tbx_addr1.setValue(ds_shipmentIndicationOrder.getCellData(info.newRowIndex, "dtlAddr1")); // 상세주소1
        tbx_addr2.setValue(ds_shipmentIndicationOrder.getCellData(info.newRowIndex, "dtlAddr2")); // 상세주소2
        tbx_stsClsCd.setValue(ds_shipmentIndicationOrder.getCellData(info.newRowIndex, "stsClsCd")); // 상태구분코드
        tbx_unqItm.setValue(ds_shipmentIndicationOrder.getCellData(info.newRowIndex, "unqItm")); // 특기사항

        if ($c.gus.cfIsNull(ds_shipmentIndicationOrder.getCellData(info.newRowIndex, "mcomOdrNo").trim())) {
            switch (ds_shipmentIndicationOrder.getCellData(info.newRowIndex, "stsClsCd").toUpperCase()) {
                case "I":
                    scwin.hid_odrJobType = DGauceConstants.TB_JOB_INSERT;
                    hid_odrDelYn.setValue(DsConstants.YN_NO);
                    break;
                case "U":
                    scwin.hid_odrJobType = DGauceConstants.TB_JOB_UPDATE;
                    hid_odrDelYn.setValue(DsConstants.YN_NO);
                    break;
                case "D":
                    scwin.hid_odrJobType = DGauceConstants.TB_JOB_DELETE;
                    hid_odrDelYn.setValue(DsConstants.YN_YES); // 상태구분에 따른 오더 삭제 여부 설정
                    break;
                default:
                    scwin.hid_odrJobType = DGauceConstants.TB_JOB_INSERT;
                    hid_odrDelYn.setValue(DsConstants.YN_NO);
                    break;
            }
            $c.gus.cfEnableObjects([tbl_order]);
            $c.gus.cfDisableBtnOnly([btn_update]);
            $c.gus.cfEnableBtnOnly([btn_save]);
            gr_shipmentIndicationCommodityList.setReadOnly("grid", false);
        } else {
            scwin.hid_odrJobType = "";
            $c.gus.cfDisableObjects(tbl_order);
            if (ds_order.getCellData(ds_order.getRowPosition(), "odrDelYn") != DsConstants.YN_YES) {
                $c.gus.cfEnableBtnOnly([btn_update]);
            } else {
                $c.gus.cfDisableBtnOnly([btn_update]);
            }

            $c.gus.cfDisableBtnOnly([btn_save]);
            gr_shipmentIndicationCommodityList.setReadOnly("grid", true);
        }

        // 이전 오더요청 정보와 변경된 항목의 색상(RED)을 표시
        if (info.newRowIndex > 0) {
            if (ds_shipmentIndicationOrder.getCellData(info.newRowIndex, "odrRecptDt") != ds_shipmentIndicationOrder.getCellData(info.newRowIndex - 1, "odrRecptDt")
                || ds_shipmentIndicationOrder.getCellData(info.newRowIndex, "odrRecptHh") != ds_shipmentIndicationOrder.getCellData(info.newRowIndex - 1, "odrRecptHh"))
                tbx_odrRecptDtm.style.color = DCSS.MANDATORY_COLOR;
            else
                tbx_odrRecptDtm.setStyle("color", scwin.defaultFontColor); // 오더접수일시

            if (ds_shipmentIndicationOrder.getCellData(info.newRowIndex, "odrCreatId") != ds_shipmentIndicationOrder.getCellData(info.newRowIndex - 1, "odrCreatId"))
                tbx_odrCreatId.style.color = DCSS.MANDATORY_COLOR;
            else
                tbx_odrCreatId.setStyle("color", scwin.defaultFontColor); // 오더생성자

            if (ds_shipmentIndicationOrder.getCellData(info.newRowIndex, "odrCreatDt") != ds_shipmentIndicationOrder.getCellData(info.newRowIndex - 1, "odrCreatDt")
                || ds_shipmentIndicationOrder.getCellData(info.newRowIndex, "odrCreatHh") != ds_shipmentIndicationOrder.getCellData(info.newRowIndex - 1, "odrCreatHh"))
                tbx_odrCreatDtm.style.color = DCSS.MANDATORY_COLOR;
            else
                tbx_odrCreatDtm.setStyle("color", scwin.defaultFontColor); // 오더생성일자

            if (ds_shipmentIndicationOrder.getCellData(info.newRowIndex, "mchtOdrKndCd") != ds_shipmentIndicationOrder.getCellData(info.newRowIndex - 1, "mchtOdrKndCd"))
                tbx_mchtOdrKndCdNm.style.color = DCSS.MANDATORY_COLOR;
            else
                tbx_mchtOdrKndCdNm.setStyle("color", scwin.defaultFontColor); // 화주오더종류

            if (ds_shipmentIndicationOrder.getCellData(info.newRowIndex, "mchtOdrNo") != ds_shipmentIndicationOrder.getCellData(info.newRowIndex - 1, "mchtOdrNo"))
                tbx_mchtOdrNo.style.color = DCSS.MANDATORY_COLOR;
            else
                tbx_mchtOdrNo.setStyle("color", scwin.defaultFontColor); // 화주오더번호

            if (ds_shipmentIndicationOrder.getCellData(info.newRowIndex, "odrDt") != ds_shipmentIndicationOrder.getCellData(info.newRowIndex - 1, "odrDt"))
                tbx_odrDt.style.color = DCSS.MANDATORY_COLOR;
            else
                tbx_odrDt.setStyle("color", scwin.defaultFontColor); // 화주오더일자

            if (ds_shipmentIndicationOrder.getCellData(info.newRowIndex, "coCdNm") != ds_shipmentIndicationOrder.getCellData(info.newRowIndex - 1, "coCdNm"))
                tbx_coCdNm.style.color = DCSS.MANDATORY_COLOR;
            else
                tbx_coCdNm.setStyle("color", scwin.defaultFontColor); // 회사

            if (ds_shipmentIndicationOrder.getCellData(info.newRowIndex, "bizLongCd") != ds_shipmentIndicationOrder.getCellData(info.newRowIndex - 1, "bizLongCd"))
                tbx_bizLongCdNm.style.color = DCSS.MANDATORY_COLOR;
            else
                tbx_bizLongCdNm.setStyle("color", scwin.defaultFontColor); // 사업장

            if (ds_shipmentIndicationOrder.getCellData(info.newRowIndex, "dmndNo") != ds_shipmentIndicationOrder.getCellData(info.newRowIndex - 1, "dmndNo"))
                tbx_dmndNoNm.style.color = DCSS.MANDATORY_COLOR;
            else
                tbx_dmndNoNm.setStyle("color", scwin.defaultFontColor); // 수요가

            if (ds_shipmentIndicationOrder.getCellData(info.newRowIndex, "arvIntendDt") != ds_shipmentIndicationOrder.getCellData(info.newRowIndex - 1, "arvIntendDt")
                || ds_shipmentIndicationOrder.getCellData(info.newRowIndex, "arvIntendHh") != ds_shipmentIndicationOrder.getCellData(info.newRowIndex - 1, "arvIntendHh"))
                tbx_arvIntendDtm.style.color = DCSS.MANDATORY_COLOR;
            else
                tbx_arvIntendDtm.setStyle("color", scwin.defaultFontColor); // 도착예정일시

            if (ds_shipmentIndicationOrder.getCellData(info.newRowIndex, "tplZip") != ds_shipmentIndicationOrder.getCellData(info.newRowIndex - 1, "tplZip"))
                tbx_zip.style.color = DCSS.MANDATORY_COLOR;
            else
                tbx_zip.setStyle("color", scwin.defaultFontColor); // 우편번호

            if (ds_shipmentIndicationOrder.getCellData(info.newRowIndex, "addr1") != ds_shipmentIndicationOrder.getCellData(info.newRowIndex - 1, "addr1"))
                tbx_addr1.style.color = DCSS.MANDATORY_COLOR;
            else
                tbx_addr1.setStyle("color", scwin.defaultFontColor); // 상세주소1

            if (ds_shipmentIndicationOrder.getCellData(info.newRowIndex, "addr2") != ds_shipmentIndicationOrder.getCellData(info.newRowIndex - 1, "addr2"))
                tbx_addr2.style.color = DCSS.MANDATORY_COLOR;
            else
                tbx_addr2.setStyle("color", scwin.defaultFontColor); // 상세주소2

            if (ds_shipmentIndicationOrder.getCellData(info.newRowIndex, "stsClsCd") != ds_shipmentIndicationOrder.getCellData(info.newRowIndex - 1, "stsClsCd"))
                tbx_stsClsCd.style.color = DCSS.MANDATORY_COLOR;
            else
                tbx_stsClsCd.setStyle("color", scwin.defaultFontColor); // 상태구분코드

            if (ds_shipmentIndicationOrder.getCellData(info.newRowIndex, "unqItm") != ds_shipmentIndicationOrder.getCellData(info.newRowIndex - 1, "unqItm"))
                tbx_unqItm.style.color = DCSS.MANDATORY_COLOR;
            else
                tbx_unqItm.setStyle("color", scwin.defaultFontColor); // 특기사항

        } else {
            tbx_odrRecptDtm.setStyle("color", scwin.defaultFontColor); // 오더접수일자
            tbx_odrCreatId.setStyle("color", scwin.defaultFontColor); // 오더생성자
            tbx_odrCreatDtm.setStyle("color", scwin.defaultFontColor); // 오더생성일자
            tbx_mchtOdrKndCdNm.setStyle("color", scwin.defaultFontColor); // 화주오더종류
            tbx_mchtOdrNo.setStyle("color", scwin.defaultFontColor); // 화주오더번호
            tbx_odrDt.setStyle("color", scwin.defaultFontColor); // 화주오더일자
            tbx_bizLongCdNm.setStyle("color", scwin.defaultFontColor); // 사업장
            tbx_arvIntendDtm.setStyle("color", scwin.defaultFontColor);    // 도착예정일시
            tbx_zip.setStyle("color", scwin.defaultFontColor); // 우편번호
            tbx_addr1.setStyle("color", scwin.defaultFontColor);   // 상세주소1
            tbx_addr2.setStyle("color", scwin.defaultFontColor);   // 상세주소2
            tbx_stsClsCd.setStyle("color", scwin.defaultFontColor);    // 상태구분코드
            tbx_unqItm.setStyle("color", scwin.defaultFontColor); // 특기사항
        }
    } else {
        tbx_ctrtClntNo.setValue(""); // 계약거래처명
        hid_ctrtClntNo.setValue(""); // 계약거래처번호

        tbx_odrRecptDtm.setValue(""); // 오더접수일자
        tbx_odrCreatId.setValue(""); // 오더생성자
        tbx_odrCreatDtmlbl.setValue("오더생성일시");
        tbx_odrCreatDtm.setValue(""); // 오더생성일자
        tbx_mchtOdrKndCdNm.setValue(""); // 화주오더종류
        tbx_mchtOdrNo.setValue(""); // 화주오더번호
        tbx_odrDt.setValue(""); // 화주오더일자
        tbx_bizLongCdNm.setValue(""); // 사업장
        tbx_arvIntendDtm.setValue("");    // 도착예정일시
        tbx_zip.setValue(""); // 우편번호
        tbx_addr1.setValue("");   // 상세주소1
        tbx_addr2.setValue("");   // 상세주소2
        tbx_stsClsCd.setValue("");    // 상태구분코드
        tbx_unqItm.setValue(""); // 특기사항

        $c.gus.cfDisableObjects(tbl_order);
        $c.gus.cfDisableObjects([btn_update]);
        $c.gus.cfDisableObjects([btn_save]);
        gr_shipmentIndicationCommodityList.setReadOnly("grid", true);
    }

    if ($c.gus.cfIsNull(scwin.hid_odrJobType)) {
        // 오더, 오더품명 정보 원래값으로 복원  
        $c.data.undoAll(ds_order);
        $c.data.undoAll(ds_orderCommodity);
    }

    if (ds_shipmentIndicationOrder.getRowCount() > 0) {
        scwin.f_setOrderInformation(scwin.hid_odrJobType); // 오더 정보 설정
    }

    scwin.ds_shipmentIndicationCommodity_OnFilter();

    tbx_totalRows.setValue(ds_shipmentIndicationCommodity.getRowCount());

    if (ds_shipmentIndicationCommodity.getRowCount() > 0) {
        scwin.f_setOrderCommodityInformation(scwin.hid_odrJobType); // 오더 품명 정보 설정
    }
};

//-------------------------------------------------------------------------
// 오더요청 품명 dataList OnLoadCompleted 처리(ondataload 이벤트는 바인드 되기전에 호출되므로 사용하면 안됨)
