//-------------------------------------------------------------------------
scwin.ds_shipmentIndicationCommodity_OnLoadCompleted = function () {
    if (ds_shipmentIndicationCommodity.getRowCount() > 0) {
        ds_shipmentIndicationCommodity.setRowPosition(0);
    }

    if (ds_shipmentIndicationCommodity.getRowCount() == 0 && ds_shipmentIndicationOrder.getRowCount() > 0 && ds_order.getRowCount() > 0) {
        tbx_totalRows.setValue(ds_shipmentIndicationCommodity.getRowCount())
        //$c.gus.cfAlertMsg("%의 " + MSG_CM_ERR_003, new Array("오더요청품명"));
        $c.gus.cfAlertMsg($p, MSG_CM_ERR_003, new Array("오더요청품명의 "));
        return;
    }
};

//-------------------------------------------------------------------------
// 오더 기본정보 dataList OnLoadCompleted 처리(ondataload 이벤트는 바인드 되기전에 호출되므로 사용하면 안됨)
// ASIS : ds_order event=OnLoadCompleted(rowCnt)
//-------------------------------------------------------------------------
scwin.ds_order_OnLoadCompleted = function () {
    if (ds_order.getRowCount() > 0) {
        ds_order.setRowPosition(0);
        // 여기수정...20061103 박홍준 (계약과 별개로 셋팅한다.)
        lc_reqClntNm.setValue(ds_order.getCellData(ds_order.getRowPosition(), "reqClntNo")); // 요청처
        lc_bilgClntNm.setValue(ds_order.getCellData(ds_order.getRowPosition(), "bilgClntNo")); // 청구처      
        //ds_bilgClntNo
    }
};

//-------------------------------------------------------------------------
// 오더 계약번호 dataList OnLoadCompleted 처리(ondataload 이벤트는 바인드 되기전에 호출되므로 사용하면 안됨)
// ASIS : ds_ctrtNo event=OnLoadCompleted(rowCnt)
//-------------------------------------------------------------------------
scwin.ds_ctrtNo_OnLoadCompleted = function () {
    if (ds_orderCommodity.getRowCount() > 0 && ds_orderCommodity.getRowCount() == 1) {
        rd_coshippingYn.setValue('0');
    } else {
        rd_coshippingYn.setValue('1');
    }

    var sub_lobran = dma_lobranQueryCondition.get("lobranCd").trim().substring(0, 2);
    if (sub_lobran == '3A') {
        ed_bilgLodeptCd.setValue("3A2");
        ed_bilgLodeptCd.hidVal = "3A2";
        ed_bilgLodeptNm.setValue("당진평택운송");
        ed_bilgLodeptNm.hidVal = "당진평택운송";
    } else if (sub_lobran == '7A') {
        ed_bilgLodeptCd.setValue("7A2");
        ed_bilgLodeptCd.hidVal = "7A2";
        ed_bilgLodeptNm.setValue("포항운송");
        ed_bilgLodeptNm.hidVal = "포항운송";
    }
};

//-------------------------------------------------------------------------
// 요청 거래처 dataList OnLoadCompleted 처리(ondataload 이벤트는 바인드 되기전에 호출되므로 사용하면 안됨)
// ASIS : ds_reqClntNo event=OnLoadCompleted(rowCnt)
//-------------------------------------------------------------------------
scwin.ds_reqClntNo_OnLoadCompleted = function () {
    if (ds_reqClntNo.getRowCount() > 0) {
        ds_reqClntNo.setRowPosition(0);
        ed_reqClntNo.setValue(ds_reqClntNo.getCellData(ds_reqClntNo.getRowPosition(), "clntNo"));
        scwin.hid_chkReqClntNo = ds_reqClntNo.getCellData(ds_reqClntNo.getRowPosition(), "clntNo");
        // ed_reqClntNo.setValue(ds_reqClntNo.getCellData(0, "clntNo"));
        // scwin.hid_chkReqClntNo = ds_reqClntNo.getCellData(0, "clntNo");
        scwin.ds_order_OnLoadCompleted();
    }
};

//-------------------------------------------------------------------------
// 청구 거래처 dataList OnLoadCompleted 처리(ondataload 이벤트는 바인드 되기전에 호출되므로 사용하면 안됨)
// ASIS : ds_bilgClntNo event=OnLoadCompleted(rowCnt)
//-------------------------------------------------------------------------
scwin.ds_bilgClntNo_OnLoadCompleted = async function () {
    if (ds_bilgClntNo.getRowCount() > 0) {
        ds_bilgClntNo.setRowPosition(0);
    }

    if (ds_shipmentIndicationOrder.getCellData(0, "bizLongCd") == "5589" && ds_ctrtNo.getCellData(ds_ctrtNo.getRowPosition(), "ctrtNo") != "선택") {
        let ret = await $c.win.confirm("청구거래처를 \'100258\' 로 설정하시겠습니까?");
        if (ret) {
            ed_bilgClntNo.setValue("100285");
            scwin.hid_chkBilgClntNo = "";
            scwin.f_bilgClntNo();
        } else {
            ed_bilgClntNo.setValue(ds_bilgClntNo.getCellData(ds_bilgClntNo.getRowPosition(), "clntNo"));
            scwin.hid_chkBilgClntNo = ds_bilgClntNo.getCellData(ds_bilgClntNo.getRowPosition(), "clntNo");
        }
    } else {
        ed_bilgClntNo.setValue(ds_bilgClntNo.getCellData(ds_bilgClntNo.getRowPosition(), "clntNo"));
        scwin.hid_chkBilgClntNo = ds_bilgClntNo.getCellData(ds_bilgClntNo.getRowPosition(), "clntNo");
    }
    scwin.ds_order_OnLoadCompleted();
};

//-------------------------------------------------------------------------
// 물류점소 영업부서 dataList ondataload
// ASIS : ds_lobranSales event=OnLoadCompleted(rowCnt)
//-------------------------------------------------------------------------
scwin.ds_lobranSales_ondataload = function () {
    if (ds_lobranSales.getRowCount() > 0) {
        ds_lobranSales.setRowPosition(0);
        var sub_lobarn = ds_lobranSales.getCellData(ds_lobranSales.getRowPosition(), "lobranCd").trim().substring(0, 2);
        if (sub_lobarn == '3A') { //당진은 1D9으로 셋팅 => 2011.01.19 당진평택 3A2 
            ed_bilgLodeptCd.setValue("3A2");
            ed_bilgLodeptCd.hidVal = "3A2";
            ed_bilgLodeptNm.setValue("당진평택운송");
            ed_bilgLodeptNm.hidVal = "당진평택운송";
        } else {
            // 청구부서 설정 < - 영업부서
            ed_bilgLodeptCd.setValue(ds_lobranSales.getCellData(ds_lobranSales.getRowPosition(), "lobranCd"));
            ed_bilgLodeptCd.hidVal = ds_lobranSales.getCellData(ds_lobranSales.getRowPosition(), "lobranCd");
            ed_bilgLodeptNm.setValue(ds_lobranSales.getCellData(ds_lobranSales.getRowPosition(), "lobranNm"));
            ed_bilgLodeptNm.hidVal = ds_lobranSales.getCellData(ds_lobranSales.getRowPosition(), "lobranNm");
        }
    }
};

//-------------------------------------------------------------------------
