//-------------------------------------------------------------------------
// 오더요청 품명 filter
// ASIS : ds_shipmentIndicationCommodity event=OnFilter(row)
//-------------------------------------------------------------------------
scwin.ds_shipmentIndicationCommodity_OnFilter = function (row) {
    var v_clntNo = ds_shipmentIndicationOrder.getCellData(ds_shipmentIndicationOrder.getRowPosition(), "clntNo");
    var v_mchtOdrKndCd = ds_shipmentIndicationOrder.getCellData(ds_shipmentIndicationOrder.getRowPosition(), "mchtOdrKndCd");
    var v_mchtOdrNo = ds_shipmentIndicationOrder.getCellData(ds_shipmentIndicationOrder.getRowPosition(), "mchtOdrNo");
    var v_logSeq = ds_shipmentIndicationOrder.getCellData(ds_shipmentIndicationOrder.getRowPosition(), "logSeq");

    // 필터 삭제 후 적용
    ds_shipmentIndicationCommodity.removeColumnFilterAll();
    $c.data.dataListFilter(ds_shipmentIndicationCommodity, "clntNo=='" + v_clntNo + "' && mchtOdrKndCd=='" + v_mchtOdrKndCd + "' && mchtOdrNo=='" + v_mchtOdrNo + "' && logSeq=='" + v_logSeq + "'");
};

