        for (var i = 0; i < ds_shipmentIndicationCommodity.getRowCount(); i++) {
            ds_shipmentIndicationCommodity.setCellData(i, "toWrkPlNm", ed_arvWrkPlNm.getValue());
            ds_shipmentIndicationCommodity.setCellData(i, "toWrkPlCd", ed_arvWrkPlCd.getValue());

            ds_orderCommodity.setCellData(i, "arvWrkPlCd", ds_shipmentIndicationCommodity.getCellData(i, "toWrkPlCd")); // 도착작업장코드
        }
    }
};
