//-------------------------------------------------------------------------
// 계약번호 콤보박스 값변경 이벤트
// ASIS : lc_ctrtNo event=OnSelChange()
//-------------------------------------------------------------------------
scwin.lc_ctrtNo_onchange = async function (info) {
    var ctrtNo = "";
    var odrCtrtNo = "";
    var v_ctrtNo = "";
    var odrNo = "";
    var mgntTrgtClntYn = ""; //거래처 관리대상여부

    v_ctrtNo = lc_ctrtNo.getValue();
    ctrtNo = scwin.hid_ctrtNo;
    odrCtrtNo = hid_odrNo.getValue();
    odrNo = ed_mcomOdrNo.getValue();

    hid_taxnClsCd.getValue(ds_ctrtNo.getCellData(ds_ctrtNo.getRowPosition(), "taxnClsCd"));
    if (ds_ctrtNo.getRowCount() > 0) {
        mgntTrgtClntYn = ds_ctrtNo.getCellData(ds_ctrtNo.getRowPosition(), "mgntTrgtClntYn");
        v_ctrtNo = ds_ctrtNo.getCellData(0,"ctrtNo");
    }

    if (lc_ctrtNo.getText(true) != "선택") {
        await scwin.f_RetrieveCtrtWrkPath(v_ctrtNo);
    }

    if (mgntTrgtClntYn == 1) {
        $c.gus.cfAlertMsg(MSG_CM_ERR_041, ["본 계약거래처", "관리대상이므로 오더등록"]); //"%은(는) %할 수 없습니다.

        // DataSet 초기화
        scwin.f_clearDataSetAll();

        $c.gus.cfDisableKeyData();
        $c.gus.cfDisableAllBtn();

        return false;
    }

    if (v_ctrtNo != "" && ds_ctrtNo.getRowCount() > 0 && v_ctrtNo != ctrtNo && odrNo == "") {
        // 2. 계약번호 별 - 요청거래처, 실화주, 청구거래처 조회
        scwin.f_clearClntDataSet();
        scwin.hid_ctrtNo = v_ctrtNo;

        //세팅 잘 안되서 넣어줌 260420
        let tempCtrtNo = lc_ctrtNo.getValue() ?? ds_ctrtNo.getCellData(0, "ctrtNo");

        dma_orderQueryCondition.set("odrNo", hid_odrNo.getValue());
        dma_orderQueryCondition.set("ctrtNo", tempCtrtNo);
        dma_orderQueryCondition.set("ctrtClntNo", hid_ctrtClntNo.getValue());
        dma_orderQueryCondition.set("odrKndCd", acb_odrKndCd.getValue());
        dma_orderQueryCondition.set("bizDivCntrYn", scwin.hid_bizDivCntrYn);
        dma_orderQueryCondition.set("bizDivBulkYn", scwin.hid_bizDivBulkYn);
        dma_orderQueryCondition.set("bizDivTplYn", scwin.hid_bizDivTplYn);
        dma_orderQueryCondition.set("transCargoClsCd", hid_transCargoClsCd.getValue());
        dma_orderQueryCondition.set("impExpDomesticClsCd", hid_impExpDomesticClsCd.getValue());
        await $c.sbm.execute(sbm_retrieveCtrtNo);

        ds_ediMappingSearch.setCellData(ds_ediMappingSearch.getRowPosition(), "osideCd", acb_mchtOdrKndCd.getValue());
        $c.sbm.execute(sbm_reterieveOdrKndCd);
    }
};

scwin.lc_ctrtNo_onviewchange = async function (info) {
    var ctrtNo = "";
    var odrCtrtNo = "";
    var v_ctrtNo = "";
    var odrNo = "";
    var mgntTrgtClntYn = ""; //거래처 관리대상여부

    v_ctrtNo = lc_ctrtNo.getValue();
    ctrtNo = scwin.hid_ctrtNo;
    odrCtrtNo = hid_odrNo.getValue();
    odrNo = ed_mcomOdrNo.getValue();

    let rowPos = ds_ctrtNo.getRowPosition();
    if (ds_ctrtNo.getRowCount() > 0&& $c.util.isEmpty(rowPos))rowPos = 0;

    hid_taxnClsCd.getValue(ds_ctrtNo.getCellData(rowPos, "taxnClsCd"));
    if (ds_ctrtNo.getRowCount() > 0) mgntTrgtClntYn = ds_ctrtNo.getCellData(rowPos, "mgntTrgtClntYn");

    if (lc_ctrtNo.getText(true) != "선택") {
        scwin.f_RetrieveCtrtWrkPath(lc_ctrtNo.getValue());

        for (var i = 0; i < ds_shipmentIndicationCommodity.getRowCount(); i++) {
            ds_shipmentIndicationCommodity.setCellData(i, "ctrtWrkPathSeq", 0);
        }
    }

    if (mgntTrgtClntYn == 1) {
        await $c.gus.cfAlertMsg(MSG_CM_ERR_041, ["본 계약거래처", "관리대상이므로 오더등록"]); //"%은(는) %할 수 없습니다.

        // DataSet 초기화
        // asis랑 똑같이 세팅하기 위해서 초기화 츃소
        // scwin.f_clearDataSetAll();
        ds_ctrtNo.removeAll();

        if (ds_ctrtNo.getRowCount() == 0 && ds_shipmentIndicationOrder.getRowCount() > 0) {
            $c.gus.cfAlertMsg($p, MSG_CM_ERR_049, new Array("거래처 " + ed_clntNm.getValue() + "의 계약번호"))
        }

        if (scwin.isParentCalled) {
            scwin.isParentCalled = false;
            scwin.sbm_reterieve_submitdone({responseJSON: {resultDataSet: [{ Code: 0 }]}});
        }

        $c.gus.cfDisableKeyData();
        $c.gus.cfDisableAllBtn();

        return false;
    }

    if (v_ctrtNo != "" && ds_ctrtNo.getRowCount() > 0 && v_ctrtNo != ctrtNo && odrNo == "") {
        // 2. 계약번호 별 - 요청거래처, 실화주, 청구거래처 조회
        scwin.f_clearClntDataSet();
        scwin.hid_ctrtNo = v_ctrtNo;

        dma_orderQueryCondition.set("odrNo", hid_odrNo.getValue());
        dma_orderQueryCondition.set("ctrtNo", lc_ctrtNo.getValue());
        dma_orderQueryCondition.set("ctrtClntNo", hid_ctrtClntNo.getValue());
        dma_orderQueryCondition.set("odrKndCd", acb_odrKndCd.getValue());
        dma_orderQueryCondition.set("bizDivCntrYn", scwin.hid_bizDivCntrYn);
        dma_orderQueryCondition.set("bizDivBulkYn", scwin.hid_bizDivBulkYn);
        dma_orderQueryCondition.set("bizDivTplYn", scwin.hid_bizDivTplYn);
        dma_orderQueryCondition.set("transCargoClsCd", hid_transCargoClsCd.getValue());
        dma_orderQueryCondition.set("impExpDomesticClsCd", hid_impExpDomesticClsCd.getValue());
        await $c.sbm.execute(sbm_retrieveCtrtNo);

        ds_ediMappingSearch.setCellData(ds_ediMappingSearch.getRowPosition(), "osideCd", acb_mchtOdrKndCd.getValue());
        $c.sbm.execute(sbm_reterieveOdrKndCd);
    }

};

