scwin.isInputActive = false;
scwin.btn_PopUp2_onclick = function (e) {
    ed_reqClntNo.commit();
    let clntNo = ed_reqClntNo.getValue();
    let clntNm = lc_reqClntNm.getText();
    if($c.util.isEmpty(clntNo)&&scwin.isInputActive){
        lc_reqClntNm.setValue("");
        scwin.isInputActive = false;
    }
    // let clntNm = ds_reqClntNo.getCellData(ds_reqClntNo.getRowPosition(), "clntNm");
    scwin.f_openCommonPopUp(2, clntNo, clntNm, 'T', 'F');
};

//-------------------------------------------------------------------------
//  요청처 검색 콜백
//------------------------------------------------------------------------- 
scwin.udc_eqClntNo_callBackFunc = function (rtnList) {
    if (rtnList != null) {
        if (rtnList[0].trim() != "N/A") {
            //return value Assign
            var chkValue = false;

            for (var idx = 0; idx < ds_reqClntNo.getRowCount(); idx++) {
                if (rtnList[0] == ds_reqClntNo.getCellData(idx, "clntNo")) {
                    lc_reqClntNm.setValue(rtnList[0]);
                    chkValue = true;
                    ed_reqClntNo.setValue(rtnList[0]); //요청 거래처코드
                    ed_reqClntNo.hidVal = rtnList[0]; //요청 거래처코드
                    scwin.hid_chkReqClntNo = rtnList[0]; //요청 거래처코드
                    break;
                }
            }

            if (!chkValue) {
                let newRow = ds_reqClntNo.insertRow();
                ds_reqClntNo.setRowPosition(newRow);
                ds_reqClntNo.setCellData(ds_reqClntNo.getRowPosition(), "clntNo", rtnList[0]); //실화주코드
                ds_reqClntNo.setCellData(ds_reqClntNo.getRowPosition(), "clntNm", rtnList[1]); //실화주명
                lc_reqClntNm.setSelectedIndex(ds_reqClntNo.getRowPosition()); //위치 이동
                ed_reqClntNo.setValue(rtnList[0]); //요청 거래처코드
                ed_reqClntNo.hidVal = rtnList[0]; //요청 거래처코드
                scwin.hid_chkReqClntNo = rtnList[0]; //요청 거래처코드
            }
        } else {
            ed_reqClntNo.setValue(ed_reqClntNo.hidVal);
        }
    } else {
        ed_reqClntNo.setValue(""); //요청 거래처코드
        ed_reqClntNo.hidVal = ""; //요청 거래처코드
        scwin.hid_chkReqClntNo = ""; //요청 거래처코드
        lc_reqClntNm.setSelectedIndex(0);
    }
};

