//------------------------------------------------------------------------------
// 작업경로 버튼 클릭
//------------------------------------------------------------------------------
scwin.f_chgWrkPath = function () {
    let mcomOdrNo = ed_mcomOdrNo.getValue();
    if (mcomOdrNo == "") {
        $c.win.alert("오더번호를 입력하십시오");
        return;
    }

    let strUrl = "/ui/tn/sd/odrmgnt/odrdtlinfo/tn_202_02_02b.xml";
    let pgmId = "tn_202_02_02b.jsp"

    let paramObj = {
        odrNo: mcomOdrNo,
        type: "retrieve"
    };

    $c.win.openMenu("벌크작업경로수정", strUrl, pgmId, paramObj, { openAction: "exist" });
};

//------------------------------------------------------------------------------
// 계약요율 버튼 클릭
//------------------------------------------------------------------------------
scwin.f_CtrtTransTrfList = function () {
    let ctrtNo = lc_ctrtNo.getValue();
    if (ctrtNo == null || ctrtNo == "") {
        $c.win.alert("계약번호가 없습니다.");
        return;
    }

    let strUrl = "/ui/tn/sd/odrmgnt/cntrodrreg/tn_201_02_10b.xml";
    let pgmId = "tn_201_02_10b.jsp"

    let paramObj = {
        ctrtNo: ctrtNo
    };

    $c.win.openMenu("계약요율", strUrl, pgmId, paramObj, { openAction: "exist" });
};

